-- Schema for Domain: compliance | Business: Life Insurance | Version: v1_mvm
-- Generated on: 2026-05-04 07:01:18

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `life_insurance_ecm`.`compliance` COMMENT 'Governs regulatory compliance obligations across all jurisdictions — NAIC, state DOI filings, SEC/FINRA for variable products, IRS 7702/72 tax compliance, AML/BSA/KYC (FinCEN), HIPAA privacy, SOX controls, DOL fiduciary (ERISA), and ORSA/ERM reporting. Owns regulatory filing calendars, market conduct examination records, suitability reviews, examination findings, remediation tracking, compliance attestation workflows, and compliance training records.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`regulatory_obligation` (
    `regulatory_obligation_id` BIGINT COMMENT 'Unique surrogate identifier for each regulatory obligation record in the master compliance registry. Serves as the primary key for all downstream joins and compliance tracking workflows.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Regulatory obligations apply to specific legal entities based on domicile state, licensed jurisdictions, lines of business. Obligation tracking must be entity-specific for compliance management.',
    `state_regulation_id` BIGINT COMMENT 'Foreign key linking to compliance.state_regulation. Business justification: A regulatory_obligation implements or is governed by a specific state_regulation. This FK establishes the relationship between the obligation and the state-specific regulatory requirement it fulfills.',
    `aml_bsa_relevance_flag` BOOLEAN COMMENT 'Indicates whether this obligation is related to AML/BSA compliance programs, including KYC, Suspicious Activity Reports (SAR), Currency Transaction Reports (CTR), or FinCEN program requirements. Drives routing to the AML compliance team.',
    `applicable_product_lines` STRING COMMENT 'Pipe-delimited list of insurance product lines to which this obligation applies (e.g., WL|UL|IUL|VUL|FIA|SPIA|LTC|DI). Null or ALL for enterprise-wide obligations. Enables scoping of compliance activities to relevant business units and product portfolios.',
    `applicable_states` STRING COMMENT 'Pipe-delimited list of US state or territory codes (2-letter USPS abbreviations) where this obligation applies (e.g., CA|NY|TX|FL). Null or ALL for federal obligations applicable in all jurisdictions. Used to scope market conduct and state DOI filing requirements.',
    `compliance_domain` STRING COMMENT 'Primary compliance program domain to which this obligation belongs. Drives assignment to the appropriate compliance team and reporting hierarchy. Examples: AML_BSA (Anti-Money Laundering/Bank Secrecy Act), KYC (Know Your Customer), HIPAA (health data privacy), SOX (Sarbanes-Oxley financial controls), ERISA_DOL (fiduciary/retirement), tax_compliance (IRS 7702/72), market_conduct (NAIC/state DOI), solvency (RBC/ORSA/ERM), suitability (FINRA), privacy (state privacy laws). [ENUM-REF-CANDIDATE: AML_BSA|KYC|HIPAA|SOX|ERISA_DOL|tax_compliance|market_conduct|solvency|suitability|privacy — 10 candidates stripped; promote to reference product]',
    `compliance_owner` STRING COMMENT 'Full name or employee identifier of the designated compliance officer or manager who owns accountability for this obligation. This individual is responsible for ensuring timely and accurate fulfillment and is the primary escalation contact.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this regulatory obligation record was first created in the compliance registry. Provides the audit trail entry point for the obligation lifecycle and supports SOX IT general controls documentation.',
    `effective_date` DATE COMMENT 'The date on which this regulatory obligation first became applicable to the company. Marks the start of the compliance obligation lifecycle. Used to determine historical applicability and retroactive filing requirements.',
    `escalation_contact` STRING COMMENT 'Full name or employee identifier of the senior officer or executive to whom this obligation is escalated if the internal preparation deadline is missed or a compliance risk is identified. Typically the Chief Compliance Officer or General Counsel.',
    `escalation_threshold_days` STRING COMMENT 'Number of calendar days before the statutory due date at which an automated escalation alert is triggered if the obligation has not been completed. Drives the compliance calendar alert engine and executive notification workflows.',
    `expiration_date` DATE COMMENT 'The date on which this regulatory obligation ceases to apply, if applicable. Null for open-ended, ongoing obligations. Populated for time-limited regulations, sunset provisions, or temporary regulatory waivers.',
    `filing_frequency` STRING COMMENT 'How often this regulatory obligation must be fulfilled. Drives the compliance calendar generation logic and deadline scheduling. ad_hoc = triggered by a specific business event (e.g., material change, acquisition); event_triggered = triggered by a policyholder or claim event. [ENUM-REF-CANDIDATE: annual|semi_annual|quarterly|monthly|ad_hoc|event_triggered|biennial — 7 candidates stripped; promote to reference product]',
    `filing_period_end_date` DATE COMMENT 'The end date of the reporting or filing period covered by this obligation instance (e.g., December 31 for an annual filing). Together with filing_period_start_date, defines the data scope for the filing.',
    `filing_period_start_date` DATE COMMENT 'The start date of the reporting or filing period covered by this obligation instance (e.g., January 1 for an annual filing). Defines the data scope for the filing and aligns with the statutory reporting period.',
    `governing_body` STRING COMMENT 'Name of the regulatory authority or governing body that mandates this obligation (e.g., NAIC, SEC, FINRA, IRS, DOL, FinCEN, FASB, State DOI — California, IAIS). Drives routing of filings and escalation contacts. [ENUM-REF-CANDIDATE: NAIC|SEC|FINRA|IRS|DOL|FinCEN|FASB|State DOI|IAIS|ACORD — promote to reference product]',
    `grace_period_days` STRING COMMENT 'Number of calendar days after the statutory due date within which the obligation may still be fulfilled without incurring a penalty, as permitted by the governing body. Zero if no grace period is allowed. Used in escalation threshold calculations.',
    `hipaa_relevance_flag` BOOLEAN COMMENT 'Indicates whether this obligation involves HIPAA Privacy Rule or Security Rule compliance, including protected health information (PHI) handling, breach notification, or business associate agreement requirements.',
    `internal_preparation_deadline` DATE COMMENT 'Enterprise-set internal deadline for completing all preparation, review, and approval activities prior to the statutory due date. Provides buffer time for quality review, legal sign-off, and executive attestation. Typically set 5–15 business days before the statutory due date.',
    `is_attestation_required` BOOLEAN COMMENT 'Indicates whether this obligation requires a formal officer or executive attestation (e.g., SOX CEO/CFO certification, ORSA officer sign-off). When true, the compliance workflow must include an attestation step before submission.',
    `is_external_filing` BOOLEAN COMMENT 'Indicates whether this obligation requires submission of a document or report to an external regulatory body (true) or is an internal compliance activity only (false), such as an internal audit or training completion record.',
    `is_material_obligation` BOOLEAN COMMENT 'Indicates whether this obligation is classified as material for SOX, ORSA, or ERM reporting purposes. Material obligations receive heightened monitoring, executive visibility, and are included in the Board-level compliance dashboard.',
    `jurisdiction_type` STRING COMMENT 'Indicates whether this obligation is imposed at the federal, state, multi-state, or international level. Drives routing to the appropriate legal and compliance team and determines which state DOI contacts are relevant.. Valid values are `federal|state|multi_state|international`',
    `last_amended_date` DATE COMMENT 'The date on which the underlying regulation or rule governing this obligation was most recently amended or updated by the governing body. Triggers a compliance review to assess whether the obligation scope, format, or deadline has changed.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this regulatory obligation record was most recently modified in the compliance registry. Used to detect stale records, trigger re-review workflows, and support audit trail requirements under SOX and NAIC market conduct standards.',
    `ldti_relevance_flag` BOOLEAN COMMENT 'Indicates whether this obligation is related to FASB ASC 944-40 Long Duration Targeted Improvements (LDTI) accounting standard compliance, including updated reserve calculations, discount rate assumptions, and enhanced disclosures for long-duration insurance contracts.',
    `obligation_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this regulatory obligation within the enterprise compliance calendar (e.g., NAIC-ORSA-ANN, IRS-7702-QTR, SEC-N-CEN-ANN). Used as the business-facing identifier in filings, dashboards, and audit correspondence.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `obligation_name` STRING COMMENT 'Full descriptive name of the regulatory obligation as recognized by the governing body (e.g., Annual ORSA Summary Report, Form N-CEN Annual Report, NAIC Risk-Based Capital Report). Used in compliance calendars, executive dashboards, and regulatory correspondence.',
    `obligation_notes` STRING COMMENT 'Free-text field for compliance team annotations, regulatory guidance interpretations, special instructions, or contextual notes relevant to fulfilling this obligation. May include references to regulatory guidance letters, no-action letters, or internal legal opinions.',
    `obligation_status` STRING COMMENT 'Current lifecycle status of the regulatory obligation within the enterprise compliance registry. active = currently enforceable; suspended = temporarily waived by regulator; retired = no longer applicable; pending_effective = enacted but not yet in force; under_review = applicability being assessed by compliance team.. Valid values are `active|suspended|retired|pending_effective|under_review`',
    `obligation_type` STRING COMMENT 'Classification of the nature of the compliance obligation. filing = periodic regulatory report submission; examination = market conduct or financial exam; attestation = SOX/officer certification; disclosure = required customer or public disclosure; training = mandatory compliance training; audit = internal or external audit; notification = event-triggered regulatory notice; registration = product or entity registration. [ENUM-REF-CANDIDATE: filing|examination|attestation|disclosure|training|audit|notification|registration — 8 candidates stripped; promote to reference product]',
    `orsa_erm_relevance_flag` BOOLEAN COMMENT 'Indicates whether this obligation is part of the ORSA or ERM reporting framework, including the annual ORSA Summary Report submitted to state regulators. Used to scope the ERM compliance calendar and Board risk reporting.',
    `pbr_relevance_flag` BOOLEAN COMMENT 'Indicates whether this obligation is related to NAIC Principle-Based Reserving (PBR) compliance, including VM-20 (life insurance reserves), VM-21 (variable annuity reserves), and VM-31 (PBR actuarial report) requirements. Used to scope actuarial compliance activities.',
    `penalty_amount_usd` DECIMAL(18,2) COMMENT 'Maximum or standard monetary penalty in US dollars that may be assessed for non-compliance with this obligation. Used in risk quantification, ERM reporting, and prioritization of compliance resources. Null if penalty is non-monetary (e.g., license suspension).',
    `penalty_description` STRING COMMENT 'Narrative description of the regulatory penalties, fines, or sanctions that may be imposed for non-compliance or late filing (e.g., $100 per day late fee, license suspension, cease and desist order). Informs risk prioritization and escalation urgency.',
    `priority_level` STRING COMMENT 'Enterprise-assigned priority classification for this obligation based on regulatory risk, penalty severity, and business impact. critical = Board-level visibility, zero tolerance for non-compliance; high = executive escalation required if at risk; medium = standard compliance monitoring; low = routine administrative obligation.. Valid values are `critical|high|medium|low`',
    `rbc_relevance_flag` BOOLEAN COMMENT 'Indicates whether this obligation is directly related to NAIC Risk-Based Capital (RBC) reporting or solvency compliance. Used to prioritize obligations in the actuarial and finance compliance calendar and to scope RBC-related remediation activities.',
    `regulation_citation` STRING COMMENT 'Formal legal or regulatory citation for the rule or statute that creates this obligation (e.g., IRC Section 7702, NAIC Model Regulation #820, ERISA Section 404, ASC 944-40 LDTI, FinCEN 31 CFR Part 1010). Enables precise traceability to source regulation for audit and legal review.',
    `renewal_cycle_months` STRING COMMENT 'Number of months in the renewal or recurrence cycle for this obligation (e.g., 12 for annual, 3 for quarterly, 1 for monthly). Used by the compliance calendar engine to auto-generate future obligation instances. Null for one-time or event-triggered obligations.',
    `responsible_department` STRING COMMENT 'Name of the internal department or business unit primarily responsible for fulfilling this obligation (e.g., Actuarial, Legal & Compliance, Finance, Tax, Operations, Investment Management). Used for workload assignment and escalation routing.',
    `source_system` STRING COMMENT 'Name of the operational system of record from which this obligation record originates or is primarily managed (e.g., Compliance Calendar System, Policy Administration System, Actuarial Valuation System). Supports data lineage and ETL traceability in the lakehouse.',
    `statutory_due_date` DATE COMMENT 'The legally mandated deadline by which this obligation must be fulfilled as specified by the governing body or regulation. For recurring obligations, this represents the due date for the current or next filing period. Failure to meet this date may result in regulatory penalties.',
    `submission_channel` STRING COMMENT 'The required or preferred method by which this obligation must be submitted to the governing body. electronic = NAIC SERFF or similar; portal = regulator-specific web portal (e.g., SEC EDGAR, IRS e-file); api = machine-to-machine submission; paper = physical mailing.. Valid values are `electronic|paper|portal|email|api|in_person`',
    `submission_format` STRING COMMENT 'The required data format or form number for the filing submission (e.g., NAIC Annual Statement Blank, Form N-CEN, Form 5500, SAR FinCEN 111, ACORD XML). Ensures the compliance team prepares the filing in the correct format required by the governing body.',
    CONSTRAINT pk_regulatory_obligation PRIMARY KEY(`regulatory_obligation_id`)
) COMMENT 'Master registry of all regulatory obligations, filing deadlines, and compliance calendar entries applicable to Life Insurance operations across all jurisdictions. Each obligation captures the governing body, regulation citation, effective date, applicability scope (product lines, states), compliance owner, filing frequency (annual, quarterly, monthly, ad hoc), statutory due date, internal preparation deadline, grace period, escalation thresholds, responsible department, and renewal cycle. Serves as the single authoritative source for what must be done, by whom, and by when — functioning as both the obligation registry and the enterprise compliance calendar for proactive deadline management.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`regulatory_filing` (
    `regulatory_filing_id` BIGINT COMMENT 'Unique surrogate identifier for each regulatory filing record in the compliance data product. Primary key for the regulatory_filing table.',
    `agency_id` BIGINT COMMENT 'Foreign key linking to agent.agency. Business justification: Some state filings are agency-specific: agency appointment/termination notifications, agency E&O coverage reporting, agency license renewals. Regulatory_filing needs agency_id to track these agency-le',
    `amended_filing_regulatory_filing_id` BIGINT COMMENT 'Reference to the original regulatory_filing_id that this record amends or corrects. Null for original filings. Enables lineage tracking across filing versions and amendment chains.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Regulatory filing preparation costs (legal, actuarial, compliance staff time) are allocated to cost centers for expense tracking, budgeting, and SOX control over compliance expenditures. Standard fina',
    `in_force_policy_id` BIGINT COMMENT 'Foreign key linking to policy.in_force_policy. Business justification: Some regulatory filings are policy-specific (e.g., variable product registrations, individual policy filings for large cases). Linking enables tracking of policy-level regulatory submissions and suppo',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Regulatory filings generate supporting documents (actuarial memos, board resolutions, exhibits, submission confirmations) that must be retained per regulatory requirements. Essential for audit trail a',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Filing fees, late filing penalties, and associated costs are journalized. Standard accounting practice for regulatory compliance expenses and penalty accruals.',
    `jurisdiction_license_id` BIGINT COMMENT 'Foreign key linking to compliance.jurisdiction_license. Business justification: Regulatory filings (e.g., annual statements, license renewal filings) are submitted for a specific jurisdiction license. Adding jurisdiction_license_id to regulatory_filing enables linking filing reco',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Regulatory filings are submitted by specific legal entities (insurance companies within a holding company structure). The regulatory_filing product currently lacks a direct legal entity FK. Adding leg',
    `market_conduct_exam_id` BIGINT COMMENT 'Foreign key linking to compliance.market_conduct_exam. Business justification: regulatory_filing.examination_reference is a denormalized string reference to a market conduct exam. Replacing it with a proper FK market_conduct_exam_id normalizes the relationship, enabling joins to',
    `policy_form_approval_id` BIGINT COMMENT 'Foreign key linking to compliance.policy_form_approval. Business justification: A regulatory filing record may represent the actual submission that resulted in a policy form approval (e.g., SERFF filing for form approval). Adding policy_form_approval_id to regulatory_filing enabl',
    `portfolio_id` BIGINT COMMENT 'Foreign key linking to investment.portfolio. Business justification: Investment-related regulatory filings (NAIC Schedule D, RBC reports, annual statement) reference specific portfolios. Real business process: statutory reporting, investment schedule preparation, portf',
    `producer_id` BIGINT COMMENT 'Foreign key linking to agent.producer. Business justification: State DOIs require filings for producer terminations for cause, E&O coverage lapses, and license revocations. Regulatory_filing tracks these producer-specific state notifications required by insurance',
    `rate_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.rate_filing. Business justification: A regulatory filing record may represent the actual submission associated with a rate filing (e.g., SERFF rate filing submission). Adding rate_filing_id to regulatory_filing enables linking the transa',
    `rbc_calculation_id` BIGINT COMMENT 'Foreign key linking to finance.rbc_calculation. Business justification: Annual statement filings include or reference RBC calculations. Direct regulatory reporting relationship - RBC filing is often part of broader annual statement filing package to state regulators.',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Regulatory filings execute specific regulatory obligations. Each filing fulfills an obligation from the master registry. The obligation defines the filing type, governing body, and jurisdiction, makin',
    `state_regulation_id` BIGINT COMMENT 'Foreign key linking to compliance.state_regulation. Business justification: A regulatory filing is submitted under a specific state regulatory framework. Adding state_regulation_id normalizes the governing regulation reference. lead_state_code is retained as it captures the o',
    `statutory_reserve_id` BIGINT COMMENT 'Foreign key linking to finance.statutory_reserve. Business justification: Annual statement regulatory filings (NAIC blank filings) directly report statutory reserves. The regulatory_filing record for an annual statement submission must reference the statutory_reserve calcul',
    `termination_event_id` BIGINT COMMENT 'Foreign key linking to agent.termination_event. Business justification: FINRA Form U5 filings and state termination notices are regulatory filings directly triggered by producer termination events. Compliance teams must link each termination-related regulatory_filing to t',
    `decision_id` BIGINT COMMENT 'Foreign key linking to underwriting.decision. Business justification: Certain underwriting decisions (STOLI determinations, declinations, replacement decisions) directly trigger mandatory regulatory filings. Regulators require traceability from the filing back to the sp',
    `acceptance_date` DATE COMMENT 'The date on which the governing body formally accepted or acknowledged the filing as complete and compliant. Null if the filing has not yet been accepted. Distinguishes submission date from regulatory acceptance, which may differ for filings requiring review.',
    `aml_transaction_type` STRING COMMENT 'For FinCEN filings, identifies whether this is a Suspicious Activity Report (SAR) or Currency Transaction Report (CTR). Applicable only to FinCEN/BSA filings. Null for non-AML filing types. Supports AML/BSA compliance tracking.. Valid values are `SAR|CTR|other`',
    `approval_date` DATE COMMENT 'The date on which the designated approver formally signed off on the filing prior to submission. Required for SOX internal control documentation and NAIC officer certification.',
    `approver_name` STRING COMMENT 'Full name of the officer or compliance official who approved the filing. Retained for audit trail and regulatory examination purposes.',
    `board_approval_date` DATE COMMENT 'The date on which the companys Board of Directors formally approved the filing prior to submission. Required for ORSA reports and certain NAIC annual statement certifications. Null for filings that do not require board-level approval.',
    `capital_adequacy_conclusion` STRING COMMENT 'The conclusion reached in the ORSA or RBC filing regarding the insurers capital adequacy relative to its risk profile (e.g., adequate, inadequate, marginal). Applicable to ORSA and RBC-related filings. Null for non-capital filings.. Valid values are `adequate|inadequate|marginal|under_review`',
    `confirmation_reference` STRING COMMENT 'The acknowledgment or confirmation number returned by the governing bodys filing system upon successful receipt of the submission (e.g., NAIC confirmation number, SEC accession number, DOL EFAST2 confirmation, FinCEN BSA tracking number). Serves as the authoritative proof of submission.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which this regulatory filing record was first created in the compliance system. Provides the audit trail entry point for the filing lifecycle. Aligns with SOX internal control documentation requirements.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for any monetary amounts reported in this filing (e.g., USD). Primarily USD for domestic US regulatory filings. Required when penalty_amount or other monetary fields are populated.. Valid values are `^[A-Z]{3}$`',
    `days_late` STRING COMMENT 'Number of calendar days by which the filing was submitted after the statutory due date. Zero or negative if filed on time. Used to assess late-filing penalties and regulatory exposure. Calculated as submission_date minus due_date.',
    `due_date` DATE COMMENT 'The statutory or regulatory deadline by which this filing must be submitted to the governing body. Used to calculate timeliness, trigger escalation workflows, and assess late-filing penalties. Derived from the regulatory calendar for the applicable filing type and jurisdiction.',
    `erisa_plan_type` STRING COMMENT 'Classification of the ERISA-covered plan reported in this DOL Form 5500 filing (e.g., group life, 401k annuity, pension, welfare). Applicable only to ERISA filings. Null for non-ERISA filing types.. Valid values are `group_life|401k_annuity|pension|welfare|other`',
    `fiduciary_designation` STRING COMMENT 'Name or role of the designated fiduciary responsible for the ERISA plan covered by this filing. Required for DOL Form 5500 and DOL fiduciary compliance under ERISA. Null for non-ERISA filing types.',
    `filing_channel` STRING COMMENT 'The transmission method used to submit the filing to the governing body (e.g., electronic via NAIC SERFF, SEC EDGAR, DOL EFAST2, FinCEN BSA E-Filing portal, or paper submission). Relevant for audit trail and submission confirmation tracking.. Valid values are `electronic|paper|portal|api`',
    `filing_form_name` STRING COMMENT 'The official name or designation of the regulatory form used for this filing (e.g., NAIC Life/Health Annual Statement, SEC Form N-4, IRS Form 1099-R, FinCEN Form 112 CTR, DOL Form 5500, ORSA Summary Report). Provides precise identification of the statutory instrument.',
    `filing_number` STRING COMMENT 'Externally-known, human-readable reference number assigned to the filing — either generated internally or assigned by the receiving regulatory body upon submission (e.g., NAIC filing reference, SEC accession number, DOL confirmation number). Used for tracking and correspondence with regulators.',
    `filing_status` STRING COMMENT 'Current lifecycle state of the regulatory filing submission. Tracks progression from internal preparation (draft) through submission to the regulator and final disposition (accepted, rejected, withdrawn). Drives compliance workflow and remediation tracking.. Valid values are `draft|submitted|accepted|rejected|under_review|withdrawn`',
    `filing_system_source` STRING COMMENT 'Name of the internal operational system or platform from which the filing data was sourced or generated (e.g., Policy Administration System, Actuarial Valuation System, Claims Management System). Supports data lineage and ETL traceability.',
    `filing_version` STRING COMMENT 'Version or amendment number of this filing submission (e.g., original, amendment_1, corrected). Tracks whether this is the initial submission or a subsequent amendment/correction filed with the governing body.',
    `is_amended` BOOLEAN COMMENT 'Indicates whether this filing is an amendment or correction to a previously submitted filing. True if this is an amended submission; False if this is the original filing. Used to distinguish original from corrected statutory submissions.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time at which this regulatory filing record was most recently modified in the compliance system. Tracks the most recent status change, amendment, or data correction. Supports audit trail and SOX change management controls.',
    `late_filing_flag` BOOLEAN COMMENT 'Indicates whether this filing was submitted after the statutory due date. True if submission_date exceeds due_date; False if filed on time. Used for compliance monitoring, penalty assessment, and regulatory examination preparation.',
    `lead_state_code` STRING COMMENT 'Two-character US state code identifying the lead state regulator for ORSA filings and multi-state regulatory submissions. The lead state coordinates review among all states where the insurer is licensed. Applicable primarily to ORSA and group-level filings.. Valid values are `^[A-Z]{2}$`',
    `notes` STRING COMMENT 'Free-text field for compliance officers to record supplemental context, internal commentary, regulator correspondence notes, or remediation instructions related to this filing. Not transmitted to the regulator; for internal compliance workflow use only.',
    `orsa_risk_categories` STRING COMMENT 'Comma-separated list of risk categories assessed in the ORSA filing (e.g., insurance_risk, market_risk, credit_risk, operational_risk, liquidity_risk). Applicable only to ORSA filings. Null for non-ORSA filing types. Supports ERM and ORSA reporting requirements.',
    `penalty_amount` DECIMAL(18,2) COMMENT 'Monetary penalty assessed by the governing body for late or deficient filing, expressed in USD. Null if no penalty was assessed. Used for financial reporting, regulatory expense tracking, and SOX control monitoring.',
    `plan_sponsor_name` STRING COMMENT 'Name of the employer or organization sponsoring the retirement or group benefit plan covered by this ERISA filing (DOL Form 5500). Applicable only to ERISA filings. Null for non-ERISA filing types.',
    `preparer_name` STRING COMMENT 'Full name of the individual responsible for preparing the regulatory filing. Retained for audit trail and regulatory examination purposes even if the employee record changes.',
    `pte_reference` STRING COMMENT 'Reference number or identifier for any Prohibited Transaction Exemption (PTE) cited in the ERISA filing (e.g., PTE 84-24, PTE 2020-02). Applicable to ERISA filings where prohibited transaction exemptions are claimed. Null for non-ERISA filing types.',
    `rejection_date` DATE COMMENT 'The date on which the governing body formally rejected the filing. Populated only when filing_status is rejected. Triggers remediation workflow and resubmission tracking.',
    `rejection_reason` STRING COMMENT 'Textual description or regulator-provided code explaining why the filing was rejected. Populated when filing_status is rejected. Used to drive remediation actions and resubmission preparation.',
    `stress_test_scenarios` STRING COMMENT 'Description or comma-separated list of stress test scenarios included in the ORSA or actuarial filing (e.g., interest_rate_shock, pandemic_mortality, equity_market_decline). Applicable to ORSA and actuarial valuation filings. Null for non-ORSA filing types.',
    `submission_date` DATE COMMENT 'The actual calendar date on which the filing was transmitted to the governing body. Compared against due_date to determine timeliness and potential late-filing exposure. Populated upon successful transmission.',
    `submission_timestamp` TIMESTAMP COMMENT 'Precise date and time (with timezone offset) at which the filing was electronically transmitted to the governing body. Provides audit-grade evidence of timely submission, particularly for filings with intraday deadlines (e.g., FinCEN CTR 15-day rule).',
    CONSTRAINT pk_regulatory_filing PRIMARY KEY(`regulatory_filing_id`)
) COMMENT 'Transactional record of every regulatory filing submitted to governing bodies — NAIC annual/quarterly statements, state DOI market conduct filings, SEC Form N-4/N-6 for variable products, FINRA filings, IRS Form 1099-R/5498, FinCEN SAR/CTR filings, ORSA reports, ERISA Form 5500 filings, and all other statutory submissions. Captures filing type, jurisdiction, submission date, due date, filing status (draft, submitted, accepted, rejected), filing period, preparer, approver, and submission confirmation reference. For ORSA filings: includes risk categories assessed, capital adequacy conclusion, stress test scenarios, board approval date, and lead state designation. For ERISA filings: includes plan sponsor, plan type (group life, 401k annuity, pension), fiduciary designation, prohibited transaction exemption (PTE) references, and DOL filing date. Serves as the single transactional record for all regulatory submissions regardless of filing type or governing body.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`market_conduct_exam` (
    `market_conduct_exam_id` BIGINT COMMENT 'Unique surrogate identifier for each market conduct examination record in the compliance system. Primary key for this entity.',
    `agency_id` BIGINT COMMENT 'Foreign key linking to agent.agency. Business justification: Market conduct exams routinely examine agency-level distribution practices, sales supervision, and complaint handling. Regulators scope exams to specific agencies. Linking market_conduct_exam to agenc',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Exam response costs (legal counsel, document production, staff time, remediation) are significant and tracked by cost center for budget variance analysis and management accountability. Required for fi',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Market conduct exams produce official exam reports (draft and final) stored in the document system. Compliance officers need to link the exam record to its primary report document for regulatory respo',
    `in_force_policy_id` BIGINT COMMENT 'Foreign key linking to policy.in_force_policy. Business justification: Market conduct exams sample specific policies for review of sales practices, underwriting, claims, and policy administration. Linking exam to sampled policies enables tracking which policies were exam',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Market conduct exams result in monetary penalties and restitution amounts that must be accrued as journal entries. Insurance finance teams book penalty accruals and restitution liabilities when exam o',
    `jurisdiction_license_id` BIGINT COMMENT 'Foreign key linking to compliance.jurisdiction_license. Business justification: A market conduct exam is conducted within a specific jurisdiction where the company holds a Certificate of Authority. Linking market_conduct_exam to jurisdiction_license enables tracking which license',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Market conduct exams are conducted against specific legal entities. Exam scope, findings, and penalties are entity-specific for regulatory accountability and financial statement impact.',
    `portfolio_id` BIGINT COMMENT 'Foreign key linking to investment.portfolio. Business justification: Market conduct exams review investment practices, variable product sales, separate account management, and portfolio compliance. Real business process: regulatory examination, investment compliance re',
    `producer_id` BIGINT COMMENT 'Foreign key linking to agent.producer. Business justification: Market conduct exams are frequently initiated due to specific producer conduct complaints (churning, misrepresentation, unsuitable sales). Regulators and compliance teams need to link exams to the imp',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: A market conduct examination is triggered by or conducted in fulfillment of a specific regulatory obligation (e.g., NAIC market conduct annual statement, state DOI examination cycle). Linking market_c',
    `state_regulation_id` BIGINT COMMENT 'Foreign key linking to compliance.state_regulation. Business justification: A market conduct exam is conducted under the authority of specific state insurance regulations. Adding state_regulation_id normalizes the governing regulatory framework. initiating_state_code is retai',
    `appeal_filed` BOOLEAN COMMENT 'Indicates whether the company has filed a formal appeal or objection to the examination findings or enforcement action. True if an appeal has been filed; False otherwise. Triggers legal hold and appeal tracking workflow.',
    `appeal_filed_date` DATE COMMENT 'Date on which the company formally filed its appeal or objection with the state DOI or administrative tribunal. Null if no appeal has been filed. Used to track appeal timelines and regulatory response deadlines.',
    `appeal_resolution` STRING COMMENT 'Outcome of the companys formal appeal of examination findings or enforcement action. Null if no appeal was filed or appeal is still pending. Values: pending (appeal filed, awaiting decision), upheld (original findings confirmed), partially_upheld (some findings modified), overturned (findings reversed), withdrawn (company withdrew appeal).. Valid values are `pending|upheld|partially_upheld|overturned|withdrawn`',
    `cap_approval_date` DATE COMMENT 'Date on which the state DOI formally approved the companys submitted Corrective Action Plan (CAP). Null if the CAP has not yet been approved or is not required. Marks the start of the formal remediation execution period.',
    `cap_submission_date` DATE COMMENT 'Actual date on which the company submitted its Corrective Action Plan (CAP) to the state DOI. Null if the CAP has not yet been submitted. Used to track timeliness of regulatory response and compliance with DOI deadlines.',
    `cap_submission_due_date` DATE COMMENT 'Deadline by which the company must submit its Corrective Action Plan (CAP) to the state DOI. Null if no CAP is required. Triggers internal compliance workflow and executive escalation if approaching without submission.',
    `company_exam_coordinator` STRING COMMENT 'Full name of the internal company employee designated as the primary point of contact and coordinator for this market conduct examination. Responsible for document production, examiner liaison, and internal response coordination.',
    `company_legal_counsel` STRING COMMENT 'Name of the internal or external legal counsel assigned to advise the company during the market conduct examination. Responsible for legal strategy, response drafting, and appeal proceedings if applicable.',
    `company_response_due_date` DATE COMMENT 'Deadline by which the company must submit its formal written response to the draft examination report findings. Calculated from the draft report issuance date per state DOI requirements. Failure to respond by this date may result in findings being finalized without company input.',
    `corrective_action_plan_required` BOOLEAN COMMENT 'Indicates whether the state DOI has required the company to submit a formal Corrective Action Plan (CAP) as a result of examination findings. True if a CAP is required; False if no formal plan is mandated. Drives the corrective action tracking workflow.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this market conduct examination record was first created in the compliance management system. Represents the system-of-record audit trail creation event. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `critical_findings_count` STRING COMMENT 'Number of examination findings classified as critical severity — representing systemic violations, significant consumer harm, or material regulatory non-compliance requiring immediate corrective action. Supports executive reporting and regulatory escalation tracking.',
    `draft_report_date` DATE COMMENT 'Date on which the state DOI issued the preliminary draft examination report to the company for review and response. Initiates the companys formal response period, which is typically 30 days under NAIC standards.',
    `exam_close_date` DATE COMMENT 'Date on which the state DOI formally closed the examination after confirming all findings have been remediated or resolved. Represents the end of the examination lifecycle. Null if the examination is still open.',
    `exam_notes` STRING COMMENT 'Free-text field for internal compliance team notes regarding the examination, including context about regulatory relationships, strategic considerations, unusual circumstances, or coordination with other regulatory matters. Not shared with the DOI.',
    `exam_number` STRING COMMENT 'Externally-assigned examination reference number issued by the initiating state Department of Insurance (DOI). Used for correspondence, filings, and cross-referencing with the regulator. Format varies by state DOI.',
    `exam_outcome` STRING COMMENT 'Regulatory outcome or enforcement action resulting from the completed examination. Captures the most severe action taken: no_action (no violations found or all minor), corrective_action_plan (formal CAP required), consent_order (negotiated regulatory agreement), cease_and_desist (order to stop specific practices), license_suspension (temporary license action), monetary_penalty (fine assessed), restitution_ordered (consumer repayment required), multi_action (multiple enforcement actions). [ENUM-REF-CANDIDATE: no_action|corrective_action_plan|consent_order|cease_and_desist|license_suspension|monetary_penalty|restitution_ordered|multi_action — promote to reference product]',
    `exam_period_end_date` DATE COMMENT 'End date of the business activity review period covered by the examination. Defines the latest date of company records and transactions subject to examiner review.',
    `exam_period_start_date` DATE COMMENT 'Start date of the business activity review period covered by the examination. Defines the earliest date of company records and transactions subject to examiner review. Typically spans 3-5 years of prior business activity.',
    `exam_scope` STRING COMMENT 'Narrative description of the business areas, product lines, and practices subject to review in this examination. May reference specific lines of business (life, annuity, disability), functional areas (claims, underwriting, sales, billing), or regulatory concerns (suitability, AML, HIPAA). Derived from the DOI examination notice.',
    `exam_status` STRING COMMENT 'Current lifecycle status of the market conduct examination from initial notification through final closure. Tracks the examination workflow stage: notification_received (DOI notice received), in_progress (active examination underway), draft_report (preliminary findings issued), response_pending (company response to draft due), final_report (final examination report issued), closed (all findings resolved), appealed (company has filed a formal appeal). [ENUM-REF-CANDIDATE: notification_received|in_progress|draft_report|response_pending|final_report|closed|appealed — promote to reference product]',
    `exam_type` STRING COMMENT 'Classification of the market conduct examination by its scope and trigger. Routine examinations are scheduled periodic reviews; targeted examinations focus on specific business practices; multi-state examinations are coordinated across multiple state DOIs; for-cause examinations are triggered by complaints or regulatory concerns; desk examinations are conducted remotely; market analysis examinations are data-driven reviews.. Valid values are `routine|targeted|multi_state|for_cause|desk|market_analysis`',
    `final_report_date` DATE COMMENT 'Date on which the state DOI issued the final examination report incorporating company responses and examiner determinations. This is the official regulatory record of examination findings and required corrective actions.',
    `functional_areas_examined` STRING COMMENT 'Comma-separated list of business functional areas reviewed during the examination (e.g., claims_adjudication, policy_servicing, sales_practices, underwriting, billing, complaint_handling, anti_money_laundering). Supports gap analysis and remediation planning.',
    `initiating_state_code` STRING COMMENT 'Two-letter USPS state abbreviation identifying the lead state Department of Insurance that initiated and is conducting the market conduct examination. For multi-state examinations, this is the lead state coordinating the review.. Valid values are `^[A-Z]{2}$`',
    `lead_examiner_contact` STRING COMMENT 'Email address or phone number of the state DOI lead examiner for official examination correspondence. Used by the companys compliance team to coordinate document requests, schedule interviews, and submit responses.',
    `lead_examiner_name` STRING COMMENT 'Full name of the state DOI lead examiner assigned to conduct and oversee the market conduct examination. Used for correspondence, scheduling, and examination record attribution. This is a regulatory contact, not a company employee.',
    `lines_of_business` STRING COMMENT 'Comma-separated list of insurance product lines included in the examination scope (e.g., whole_life, term_life, annuity, disability_income, long_term_care). Aligns with NAIC line-of-business classifications. Supports product-level finding analysis and trend reporting.',
    `major_findings_count` STRING COMMENT 'Number of examination findings classified as major severity — representing significant but non-systemic violations requiring formal corrective action plans. Supports prioritization of remediation resources.',
    `minor_findings_count` STRING COMMENT 'Number of examination findings classified as minor severity — representing isolated or technical violations with limited consumer impact. Typically addressed through process improvements rather than formal corrective action plans.',
    `monetary_penalty_amount` DECIMAL(18,2) COMMENT 'Total monetary penalty or fine assessed by the state DOI as a result of this examination, expressed in US dollars. Null if no monetary penalty was assessed. Supports financial exposure tracking, SOX controls, and regulatory liability reporting. Classified as confidential due to business-sensitive financial exposure.',
    `notification_date` DATE COMMENT 'Date on which the company received official written notification from the state Department of Insurance of the upcoming or initiated market conduct examination. Triggers internal response timelines and document preservation obligations.',
    `onsite_end_date` DATE COMMENT 'Date on which the active on-site (or remote desk) examination phase concluded and examiners departed or ceased active record review. Marks the transition to report drafting phase.',
    `onsite_start_date` DATE COMMENT 'Date on which examiners physically arrived at company premises (or commenced remote access for desk examinations) to begin active review of records and interviews. Null for market analysis examinations that are entirely data-driven.',
    `participating_states` STRING COMMENT 'Comma-separated list of two-letter USPS state abbreviations for all states participating in a multi-state market conduct examination, excluding the initiating state. Null or empty for single-state examinations. Supports multi-state coordination tracking per NAIC protocols.',
    `prior_exam_reference` STRING COMMENT 'Examination number of the prior market conduct examination that this examination follows up on, if applicable. Null if this is not a repeat examination. Enables linkage between examination cycles for repeat-finding trend analysis.',
    `repeat_exam_indicator` BOOLEAN COMMENT 'Indicates whether this examination is a follow-up or repeat examination triggered by unresolved findings from a prior examination cycle. True if this is a repeat examination; False if it is an initial examination. Critical for repeat-finding trend analysis and regulatory escalation risk assessment.',
    `restitution_amount` DECIMAL(18,2) COMMENT 'Total amount of consumer restitution ordered by the state DOI as a result of examination findings, expressed in US dollars. Represents payments owed to policyholders harmed by identified violations. Null if no restitution was ordered. Classified as confidential due to business-sensitive financial exposure.',
    `total_findings_count` STRING COMMENT 'Total number of distinct examination findings identified across all severity levels in this examination. Provides a high-level measure of examination outcome severity and supports trend analysis across examination cycles.',
    `total_policies_examined` STRING COMMENT 'Total number of individual policy or contract records reviewed by examiners during the examination. Represents the full sample size across all functional areas and lines of business examined. Used to calculate error rates and assess statistical significance of findings.',
    `total_policies_with_findings` STRING COMMENT 'Total number of policy or contract records in which at least one examination finding was identified. Used to calculate the overall error rate (policies with findings / total policies examined) and assess the breadth of non-compliance.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this market conduct examination record was most recently modified in the compliance management system. Supports audit trail, change detection, and incremental ETL processing. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    CONSTRAINT pk_market_conduct_exam PRIMARY KEY(`market_conduct_exam_id`)
) COMMENT 'Comprehensive record of state DOI market conduct examinations, their associated findings, and finding-level detail. Captures examination type (routine, targeted, multi-state), initiating state DOI, scope, lead examiner, examination period, status, and outcome. Includes embedded finding records: finding description, regulatory citation violated, severity classification (critical, major, minor), affected policy counts, examiner recommendations, company response, finding status (open, disputed, remediated, closed), and corrective action deadlines. Supports the full examination lifecycle from notification through finding closure and repeat-finding trend analysis across examination cycles.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`exam_finding` (
    `exam_finding_id` BIGINT COMMENT 'Unique surrogate identifier for each individual finding or deficiency identified during a market conduct examination, regulatory audit, or internal compliance review.',
    `asset_holding_id` BIGINT COMMENT 'Foreign key linking to investment.asset_holding. Business justification: Exam findings may cite specific investment holdings violating regulations (non-admitted assets, concentration violations, prohibited investments). Real business process: examination remediation, asset',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Exam findings are assigned to responsible departments for remediation cost tracking and internal charge-back. The estimated_financial_exposure on each finding must be allocated to a cost center for fi',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Each exam finding requires supporting evidence documents, examiner work papers, and company response documentation. Critical for finding remediation workflow and regulatory closure. Replaces text refe',
    `in_force_policy_id` BIGINT COMMENT 'Foreign key linking to policy.in_force_policy. Business justification: Exam findings often cite specific policy examples as evidence of deficiencies. Linking enables tracking which policies exhibited the deficiency, supports remediation verification, and enables regulato',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Exam findings resulting in penalties, consumer restitution, or remediation costs generate journal entries. Finance must track exam-related expenses for financial statement accuracy and regulatory repo',
    `jurisdiction_license_id` BIGINT COMMENT 'Foreign key linking to compliance.jurisdiction_license. Business justification: An exam finding may identify a jurisdiction license deficiency (e.g., transacting business in a state without proper Certificate of Authority, unauthorized lines of business). Adding jurisdiction_lice',
    `market_conduct_exam_id` BIGINT COMMENT 'Reference to the parent market conduct examination or regulatory audit under which this finding was raised.',
    `plan_id` BIGINT COMMENT 'Foreign key linking to product.plan. Business justification: Market conduct exam findings are tied to specific product plans (e.g., finding about policy form or sales practice for Plan X). Product managers need direct plan-level finding reports for remediation ',
    `policy_form_approval_id` BIGINT COMMENT 'Foreign key linking to compliance.policy_form_approval. Business justification: Market conduct exams frequently examine whether policy forms are properly approved and filed. An exam finding may identify a specific policy form approval deficiency (e.g., using unapproved form langu',
    `prior_finding_exam_finding_id` BIGINT COMMENT 'Reference to the earlier exam_finding record that this finding repeats or is related to, enabling repeat-finding lineage and trend analysis.',
    `rate_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.rate_filing. Business justification: Exam findings frequently identify rate filing deficiencies (e.g., charging rates not filed with the DOI, improper rate increases). Adding rate_filing_id to exam_finding enables direct traceability fro',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Exam findings may identify failures to meet regulatory obligations. The finding describes the deficiency, while the obligation describes the requirement.',
    `schedule_id` BIGINT COMMENT 'Foreign key linking to commission.commission_schedule. Business justification: Market conduct exam findings often cite specific commission schedules as evidence of improper incentives, anti-rebating violations, or excessive compensation. Real business process: regulatory examina',
    `decision_id` BIGINT COMMENT 'Foreign key linking to underwriting.decision. Business justification: Market conduct exam findings frequently cite specific underwriting decisions as the subject of non-compliance (e.g., improper declination, discriminatory rating, inadequate financial underwriting). Di',
    `actual_penalty_amount` DECIMAL(18,2) COMMENT 'Actual monetary penalty or fine levied by the regulatory authority as a result of this finding (USD). Null if no penalty was assessed.',
    `actual_remediation_date` DATE COMMENT 'Date on which the company completed all corrective actions and the finding was substantively remediated, used to measure remediation cycle time against target.',
    `affected_business_process` STRING COMMENT 'The core business process or operational area implicated by the finding (e.g., Policy Underwriting and Risk Assessment, Premium Billing and Collection, Claims Adjudication and Settlement, Annuity Contract Administration, Agent and Broker Commission Management). [ENUM-REF-CANDIDATE: policy_underwriting|new_business_application|premium_billing|claims_adjudication|annuity_administration|policy_servicing|reinsurance_treaty|actuarial_valuation|commission_management|investment_portfolio — promote to reference product]',
    `affected_data_domain` STRING COMMENT 'The primary data domain impacted by the finding, used to route remediation ownership and cross-domain impact analysis. [ENUM-REF-CANDIDATE: policyholder|policy|underwriting|claims|billing|annuity|reinsurance|actuarial|investment|agent_distribution|product|compliance|finance|commission|document_management — 15 candidates stripped; promote to reference product]',
    `aml_bsa_related` BOOLEAN COMMENT 'Indicates whether this finding relates to AML/BSA compliance obligations, including KYC deficiencies, suspicious activity reporting failures, or FinCEN regulatory requirements.',
    `closure_date` DATE COMMENT 'Date on which the examining authority or internal compliance function formally accepted the remediation and closed the finding.',
    `company_response` STRING COMMENT 'Official company response to the finding, including acceptance, dispute rationale, or proposed corrective action plan submitted to the examining authority.',
    `compliance_attestation_required` BOOLEAN COMMENT 'Indicates whether a formal compliance attestation from a senior officer or compliance officer is required to close this finding, as mandated by the examining authority or internal governance policy.',
    `consumer_restitution_amount` DECIMAL(18,2) COMMENT 'Total monetary restitution ordered or voluntarily paid to affected policyholders or annuity contract holders as a result of this finding (USD).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this exam finding record was first created in the compliance management system, used for audit trail and data lineage.',
    `escalation_level` STRING COMMENT 'Current escalation tier for this finding based on severity, age, or regulatory sensitivity: none (routine tracking), management (department head notified), executive (C-suite involvement), board (board audit committee notified), regulator (formal regulatory escalation).. Valid values are `none|management|executive|board|regulator`',
    `estimated_financial_exposure` DECIMAL(18,2) COMMENT 'Estimated monetary exposure or potential liability associated with the finding, including potential regulatory fines, consumer restitution, or remediation costs (USD). Used for ERM and RBC impact assessment.',
    `examination_period_end_date` DATE COMMENT 'End date of the examination or audit period during which the underlying conduct or deficiency occurred.',
    `examination_period_start_date` DATE COMMENT 'Start date of the examination or audit period during which the underlying conduct or deficiency occurred, defining the scope of the review.',
    `examination_report_reference` STRING COMMENT 'Document reference number or citation pointing to the official examination report, audit report, or internal compliance review document in which this finding is formally recorded.',
    `examiner_name` STRING COMMENT 'Full name of the lead examiner or auditor from the regulatory authority or internal compliance team who identified and documented this finding.',
    `examiner_organization` STRING COMMENT 'Name of the organization or agency the examiner represents (e.g., Texas Department of Insurance, FINRA District 6, Internal Audit Division).',
    `examiner_recommendation` STRING COMMENT 'Formal recommendation or corrective action prescribed by the examiner or auditor to resolve the finding, as stated in the examination report.',
    `finding_description` STRING COMMENT 'Detailed narrative description of the finding, deficiency, or violation as documented by the examiner or internal compliance reviewer, including factual basis and observed conduct.',
    `finding_identified_date` DATE COMMENT 'The real-world date on which the examiner or auditor first identified and documented this finding during the examination or review period.',
    `finding_number` STRING COMMENT 'Externally-known alphanumeric identifier assigned to this finding by the examining authority or internal compliance team, used in official correspondence and remediation tracking (e.g., NAIC-2024-F00123).. Valid values are `^[A-Z]{2,6}-[0-9]{4}-F[0-9]{3,5}$`',
    `finding_status` STRING COMMENT 'Current workflow status of the finding in the remediation lifecycle: open (active deficiency), disputed (company contests the finding), remediated (corrective action completed), closed (examiner accepted resolution), pending_verification (awaiting examiner confirmation).. Valid values are `open|disputed|remediated|closed|pending_verification`',
    `finding_title` STRING COMMENT 'Short, descriptive title summarizing the nature of the finding or deficiency (e.g., Failure to Provide Required Policy Disclosure Within Statutory Timeframe).',
    `finding_type` STRING COMMENT 'Category of examination or review that produced this finding. [ENUM-REF-CANDIDATE: market_conduct|financial_examination|internal_audit|regulatory_audit|sox_control|aml_bsa|hipaa_privacy|finra_review|dol_erisa — promote to reference product]',
    `hipaa_related` BOOLEAN COMMENT 'Indicates whether this finding involves a HIPAA privacy or security rule violation related to protected health information (PHI) accessed or processed during underwriting, claims, or policy servicing.',
    `impacted_policy_count` STRING COMMENT 'Number of insurance policies or annuity contracts directly affected by the deficiency identified in this finding, used to assess consumer harm scope and remediation effort.',
    `impacted_transaction_count` STRING COMMENT 'Number of individual transactions (e.g., premium payments, claims, disbursements) directly affected by the deficiency, used alongside impacted_policy_count for full scope assessment.',
    `is_repeat_finding` BOOLEAN COMMENT 'Indicates whether this finding is a recurrence of a previously identified deficiency from a prior examination cycle, used for repeat-finding analysis and escalation prioritization.',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter US state or territory code identifying the jurisdiction in which the finding applies or was raised by a State Department of Insurance (DOI) or other state-level regulator.. Valid values are `^[A-Z]{2}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this exam finding record, used for change tracking, audit trail, and incremental data pipeline processing.',
    `regulatory_authority` STRING COMMENT 'The governing body or regulatory authority that identified or has jurisdiction over this finding (e.g., NAIC, state DOI, SEC, FINRA, IRS, DOL, FinCEN). [ENUM-REF-CANDIDATE: NAIC|state_doi|SEC|FINRA|IRS|DOL|FASB|FinCEN|IAIS|ACORD — 10 candidates stripped; promote to reference product]',
    `regulatory_citation` STRING COMMENT 'Specific statute, regulation, rule, or code section violated or at issue (e.g., NAIC Model Regulation 641, IRC Section 7702, HIPAA 45 CFR §164.502, SOX Section 404, FINRA Rule 2111 Suitability).',
    `remediation_owner` STRING COMMENT 'Name or identifier of the internal business owner or department responsible for executing the remediation plan and driving the finding to closure.',
    `remediation_plan` STRING COMMENT 'Detailed description of the corrective action plan developed by the company to address the finding, including process changes, system updates, training, or policy revisions.',
    `severity_classification` STRING COMMENT 'Risk-based severity level assigned to the finding: critical (systemic violation with significant consumer harm or regulatory penalty risk), major (material deficiency requiring prompt remediation), minor (isolated or low-impact deficiency), informational (observation without formal violation).. Valid values are `critical|major|minor|informational`',
    `sox_control_reference` STRING COMMENT 'Reference to the specific SOX internal control identifier or control objective that this finding relates to, used for SOX Section 302/404 compliance reporting and control deficiency tracking.',
    `suitability_review_required` BOOLEAN COMMENT 'Indicates whether this finding requires a suitability review of affected transactions or policies under FINRA Rule 2111, DOL fiduciary standards, or NAIC Suitability in Annuity Transactions Model Regulation.',
    `target_remediation_date` DATE COMMENT 'Committed target date by which the company plans to complete all corrective actions and submit evidence of remediation to the examining authority.',
    `training_required` BOOLEAN COMMENT 'Indicates whether mandatory compliance training has been identified as part of the corrective action plan for this finding, applicable to affected business units or agents.',
    CONSTRAINT pk_exam_finding PRIMARY KEY(`exam_finding_id`)
) COMMENT 'Individual finding or deficiency identified during a market conduct examination, regulatory audit, or internal compliance review. Captures finding description, regulatory citation violated, severity classification (critical, major, minor), affected business process, number of impacted policies or transactions, examiner recommendation, company response, and finding status (open, disputed, remediated, closed). Supports remediation tracking and repeat-finding analysis.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`remediation_plan` (
    `remediation_plan_id` BIGINT COMMENT 'Unique surrogate identifier for the remediation plan record in the compliance tracking system. Primary key for this entity.',
    `aml_case_id` BIGINT COMMENT 'Foreign key linking to compliance.aml_case. Business justification: AML/BSA deficiencies identified through investigations require formal remediation plans (e.g., enhanced due diligence procedures, transaction monitoring improvements). Adding aml_case_id to remediatio',
    `chargeback_rule_id` BIGINT COMMENT 'Foreign key linking to commission.chargeback_rule. Business justification: Remediation plans for churning or replacement-related exam findings often require modification of chargeback rules — e.g., extending chargeback periods or removing exemptions as corrective action. Com',
    `compensation_contract_id` BIGINT COMMENT 'Foreign key linking to commission.compensation_contract. Business justification: Remediation plans addressing compensation-related exam findings require modification or termination of specific compensation contracts. The remediation_plan already links to schedule (rate table) but ',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Remediation plans require documented validation evidence, corrective action documentation, and regulatory acceptance letters. Essential for CAP tracking and regulatory closure process. Replaces text r',
    `compliance_breach_id` BIGINT COMMENT 'Foreign key linking to investment.compliance_breach. Business justification: Remediation plans address internal investment compliance breaches (not just exam findings). Real business process: breach remediation, corrective action tracking, investment committee oversight. Essen',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Remediation costs (system changes, process improvements, training, restitution) must be budgeted and tracked by responsible cost center. Finance teams need this for expense forecasting and actual-vs-b',
    `exam_finding_id` BIGINT COMMENT 'Reference to the examination finding, audit observation, or self-identified compliance deficiency that triggered the creation of this remediation plan.',
    `in_force_policy_id` BIGINT COMMENT 'Foreign key linking to policy.in_force_policy. Business justification: Remediation plans may require policy-level corrections (e.g., premium adjustments, beneficiary corrections, illustration re-delivery). Linking enables tracking affected policies, supports remediation ',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Remediation costs (system changes, process improvements, restitution) are journalized as incurred. Finance needs to track actual vs estimated costs for accrual accuracy and budget variance analysis.',
    `jurisdiction_license_id` BIGINT COMMENT 'Foreign key linking to compliance.jurisdiction_license. Business justification: Jurisdiction license deficiencies (e.g., lapsed Certificate of Authority, unauthorized lines of business) require formal remediation plans. Adding jurisdiction_license_id to remediation_plan enables t',
    `market_conduct_exam_id` BIGINT COMMENT 'Reference to the regulatory examination, audit engagement, or compliance review that produced the finding requiring remediation.',
    `policy_form_approval_id` BIGINT COMMENT 'Foreign key linking to compliance.policy_form_approval. Business justification: Policy form approval deficiencies (e.g., using unapproved forms, missing required disclosures) require formal remediation plans. Adding policy_form_approval_id to remediation_plan enables tracking of ',
    `prior_plan_remediation_plan_id` BIGINT COMMENT 'Reference to the previous remediation plan for the same or related deficiency, when recurrence_indicator is true. Enables lineage tracking of repeat findings and demonstrates the history of compliance gap closure attempts to regulators.',
    `privacy_incident_id` BIGINT COMMENT 'Foreign key linking to compliance.privacy_incident. Business justification: A formal remediation plan is created in response to HIPAA privacy incidents and data breaches. Adding privacy_incident_id to remediation_plan enables tracking of remediation plans created for privacy ',
    `rate_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.rate_filing. Business justification: Rate filing deficiencies (e.g., charging unapproved rates, improper rate increases) require formal remediation plans including consumer restitution and corrective filings. Adding rate_filing_id to rem',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Remediation plans address failures to meet regulatory obligations. The obligation defines the regulatory deadline that the remediation must meet.',
    `sar_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.sar_filing. Business justification: SAR filing deficiencies (e.g., late filing, incomplete narrative, missed filing obligations) require formal remediation plans to improve AML/BSA compliance processes. Adding sar_filing_id to remediati',
    `schedule_id` BIGINT COMMENT 'Foreign key linking to commission.commission_schedule. Business justification: Remediation plans may require modification or elimination of specific commission schedules found to violate regulations (excessive rates, improper incentives, anti-rebating violations). Business proce',
    `suitability_review_id` BIGINT COMMENT 'Foreign key linking to compliance.suitability_review. Business justification: When suitability_review.remediation_required_flag is true, a formal remediation plan is created. Adding suitability_review_id to remediation_plan enables tracking of remediation plans created in respo',
    `actual_completion_date` DATE COMMENT 'The date on which all corrective actions were fully implemented and the remediation plan was operationally closed. Null until completion is achieved. Used to measure on-time performance against target completion date.',
    `affected_business_domain` STRING COMMENT 'The primary business domain or operational area impacted by the compliance deficiency. Used to route remediation ownership and for cross-domain compliance gap analysis. [ENUM-REF-CANDIDATE: policy|underwriting|claims|billing|annuity|reinsurance|actuarial|investment|distribution|compliance|finance|product — promote to reference product]',
    `board_notification_required` BOOLEAN COMMENT 'Indicates whether the Board of Directors or Audit Committee must be formally notified of this compliance deficiency and remediation plan per SOX, ORSA, or state DOI requirements. Drives governance reporting workflows.',
    `compliance_notes` STRING COMMENT 'Free-text field for compliance officers to record supplementary observations, regulatory correspondence summaries, interim status updates, or contextual information not captured in structured fields. Supports the full audit narrative.',
    `corrective_action_description` STRING COMMENT 'Detailed description of the specific corrective actions, process changes, system enhancements, or control improvements planned or implemented to address the identified compliance deficiency and prevent recurrence.',
    `corrective_action_type` STRING COMMENT 'Classification of the primary corrective action approach being taken. Used for portfolio analysis of remediation strategies across the enterprise. [ENUM-REF-CANDIDATE: process_change|system_enhancement|policy_update|training|control_implementation|staffing|vendor_remediation|monitoring_enhancement — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this remediation plan record was first created in the compliance tracking system. Provides the audit trail entry point for the full lifecycle of the remediation obligation.',
    `deficiency_description` STRING COMMENT 'Detailed narrative description of the compliance deficiency, gap, or violation identified. Captures the nature of the non-compliance, the regulatory requirement violated, and the scope of impact on policyholders or business operations.',
    `escalation_required` BOOLEAN COMMENT 'Indicates whether this remediation plan requires escalation to senior management, the Board of Directors, or regulatory authorities due to severity, financial exposure, or regulatory mandate. Triggers escalation workflow in the compliance management system.',
    `estimated_policyholder_impact_count` STRING COMMENT 'Estimated number of policyholders or contract holders potentially affected by the compliance deficiency. Used for regulatory reporting, consumer harm assessments, and prioritization of remediation urgency.',
    `financial_exposure_amount` DECIMAL(18,2) COMMENT 'Estimated financial exposure or potential liability associated with the compliance deficiency, expressed in USD. Includes potential regulatory fines, restitution to policyholders, and remediation costs. Used for risk quantification and ERM reporting.',
    `jurisdiction_code` STRING COMMENT 'Two- or three-character code identifying the regulatory jurisdiction (US state, territory, or federal) under which the remediation obligation arises. Uses standard USPS state abbreviations or FED for federal-level requirements.. Valid values are `^[A-Z]{2,3}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this remediation plan record was most recently modified. Used for change tracking, audit trail maintenance, and incremental data pipeline processing in the Databricks Silver layer.',
    `plan_open_date` DATE COMMENT 'The business date on which the remediation plan was formally opened and accepted as a compliance obligation. Represents the start of the remediation lifecycle and is used to calculate aging and regulatory deadline compliance.',
    `plan_status` STRING COMMENT 'Current lifecycle state of the remediation plan. Tracks progression from initial planning through corrective action execution to regulatory acceptance. [ENUM-REF-CANDIDATE: planned|in_progress|completed|validated|closed|cancelled — promote to reference product]. Valid values are `planned|in_progress|completed|validated|closed|cancelled`',
    `plan_title` STRING COMMENT 'Short, descriptive title summarizing the nature of the compliance deficiency and the corrective action being taken. Used in dashboards, reports, and regulatory submissions.',
    `plan_type` STRING COMMENT 'Classification of the remediation plan by the source of the triggering deficiency. Distinguishes between plans arising from regulatory examinations, internal audits, SOX control failures, market conduct reviews, or self-identified gaps. [ENUM-REF-CANDIDATE: regulatory_exam|internal_audit|self_identified|sox_control|market_conduct|aml_bsa|hipaa|erisa — promote to reference product]. Valid values are `regulatory_exam|internal_audit|self_identified|sox_control|market_conduct`',
    `priority_level` STRING COMMENT 'Operational priority assigned to the remediation plan, which may differ from severity level based on regulatory deadlines, resource constraints, or strategic risk appetite. Drives scheduling and resource allocation decisions.. Valid values are `urgent|high|medium|low`',
    `recurrence_indicator` BOOLEAN COMMENT 'Indicates whether this compliance deficiency is a repeat finding from a prior examination or audit cycle. Repeat findings typically receive heightened regulatory scrutiny and may result in escalated enforcement actions under NAIC and state DOI standards.',
    `regulator_reference_number` STRING COMMENT 'The reference number or docket number assigned by the regulatory authority (state DOI, NAIC, SEC, FinCEN, etc.) to track this remediation obligation in their examination or enforcement records. Used for cross-referencing regulatory correspondence.',
    `regulatory_acceptance_date` DATE COMMENT 'The date on which the regulator or examining authority formally accepted the remediation plan as satisfactorily completed. Null until regulatory acceptance is received. Marks the end of the regulatory obligation lifecycle.',
    `regulatory_acceptance_status` STRING COMMENT 'Status of the regulators or examining authoritys formal acceptance of the remediation plan closure. Tracks whether the state DOI, NAIC, SEC, FinCEN, or other governing body has acknowledged that the deficiency has been satisfactorily resolved.. Valid values are `pending|accepted|rejected|under_review`',
    `regulatory_framework` STRING COMMENT 'Primary regulatory or compliance framework under which this remediation plan is required. Identifies the governing body or standard driving the corrective action obligation. [ENUM-REF-CANDIDATE: NAIC|SOX|HIPAA|AML_BSA|ERISA|SEC_FINRA|IRS_7702|ORSA|STATE_DOI|IFRS — promote to reference product]',
    `remediation_cost_amount` DECIMAL(18,2) COMMENT 'Actual or estimated cost incurred to implement the corrective actions under this remediation plan, expressed in USD. Includes internal labor, system changes, third-party consulting, and training costs. Used for compliance budget management.',
    `responsible_department` STRING COMMENT 'Name of the business unit or department accountable for executing the remediation plan. Used for enterprise-wide compliance gap analysis and departmental accountability reporting.',
    `responsible_owner_name` STRING COMMENT 'Full name of the individual accountable for executing the remediation plan. Retained as a denormalized field for regulatory reporting and audit trail purposes where the employee record may change over time.',
    `revised_target_date` DATE COMMENT 'Updated target completion date when the original target date has been formally extended due to scope changes, resource constraints, or regulatory negotiation. Null if no revision has occurred.',
    `root_cause_category` STRING COMMENT 'Categorical classification of the root cause to enable enterprise-wide trend analysis and systemic issue identification across remediation plans. [ENUM-REF-CANDIDATE: process_gap|system_failure|training_deficiency|control_weakness|data_quality|staffing|vendor_failure|policy_gap — promote to reference product]',
    `root_cause_description` STRING COMMENT 'Formal root cause analysis narrative identifying the underlying process, system, control, or organizational failure that led to the compliance deficiency. Essential for preventing recurrence and demonstrating thoroughness to regulators.',
    `severity_level` STRING COMMENT 'Risk-based severity rating of the underlying compliance deficiency, used to prioritize remediation efforts and escalation thresholds. Critical findings typically require immediate regulatory notification under NAIC and state DOI standards.. Valid values are `critical|high|medium|low`',
    `target_completion_date` DATE COMMENT 'The committed date by which all corrective actions under this remediation plan are expected to be fully implemented and validated. May be set by regulatory mandate or internal commitment to the examining authority.',
    `validation_date` DATE COMMENT 'The date on which the validation of corrective action effectiveness was completed and documented. Null until validation is performed. Distinct from actual completion date, as validation may occur after implementation.',
    `validation_method` STRING COMMENT 'The approach used to verify that corrective actions have been effectively implemented and the compliance deficiency has been resolved. Determines the rigor and independence of the closure evidence. [ENUM-REF-CANDIDATE: internal_testing|independent_review|regulatory_inspection|third_party_audit|management_attestation|continuous_monitoring — promote to reference product]. Valid values are `internal_testing|independent_review|regulatory_inspection|third_party_audit|management_attestation`',
    `validation_outcome` STRING COMMENT 'Result of the validation testing or review confirming whether the corrective actions have been effectively implemented and the deficiency has been resolved. A failed or partially passed outcome requires additional remediation.. Valid values are `passed|failed|partially_passed|pending`',
    CONSTRAINT pk_remediation_plan PRIMARY KEY(`remediation_plan_id`)
) COMMENT 'Formal remediation plan created in response to exam findings, audit observations, or self-identified compliance deficiencies. Tracks root cause analysis, corrective action description, responsible owner, target completion date, actual completion date, remediation status (planned, in-progress, completed, validated), validation method, and regulatory acceptance status. Enables enterprise-wide tracking of compliance gap closure.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`suitability_review` (
    `suitability_review_id` BIGINT COMMENT 'Primary key for suitability_review',
    `appointment_id` BIGINT COMMENT 'Foreign key linking to agent.appointment. Business justification: Suitability reviews are conducted under a producers specific appointment authority (the appointment defines the state and product line authorization). Linking suitability_review to appointment enable',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Suitability review programs are conducted by specific compliance departments whose costs are allocated to cost centers for budgeting and regulatory expense reporting. Insurance companies track suitabi',
    `license_id` BIGINT COMMENT 'Foreign key linking to agent.license. Business justification: Suitability reviews must verify producer held valid license in jurisdiction at time of sale, with correct line of authority for product sold. License_id links review to specific license record for com',
    `party_id` BIGINT COMMENT 'Reference to the policyholder or annuity contract owner whose financial profile and suitability is being assessed at the time of sale.',
    `plan_id` BIGINT COMMENT 'Reference to the insurance or annuity product recommended and sold, used to assess product-specific suitability criteria.',
    `plan_version_id` BIGINT COMMENT 'Foreign key linking to product.plan_version. Business justification: Suitability reviews are conducted for the specific plan version sold. The plan_version determines charges, surrender schedules, and disclosures that must be reviewed. Reg BI and NAIC Suitability Model',
    `producer_id` BIGINT COMMENT 'Reference to the licensed agent or broker who conducted the sale and is responsible for the suitability determination.',
    `schedule_id` BIGINT COMMENT 'Foreign key linking to commission.commission_schedule. Business justification: Suitability reviews evaluate whether commission structure incentivized unsuitable sales (excessive FYC rates, high bonuses for specific products). Real business process: compliance review links produc',
    `state_regulation_id` BIGINT COMMENT 'Foreign key linking to compliance.state_regulation. Business justification: Suitability reviews must comply with state-specific suitability and best-interest regulations. The review describes the assessment, while the regulation describes the state-specific rules.',
    `suitability_rule_id` BIGINT COMMENT 'Foreign key linking to product.suitability_rule. Business justification: Each suitability review is conducted against the applicable product suitability_rule defining minimum income, net worth, and risk tolerance thresholds. Compliance officers must link each review to the',
    `application_id` BIGINT COMMENT 'Foreign key linking to underwriting.application. Business justification: Suitability reviews are performed ON applications during underwriting. Regulatory requirement to validate product suitability before issue. Natural 1:N (one application may have multiple suitability r',
    `aml_kyc_verified_flag` BOOLEAN COMMENT 'Indicates whether AML/KYC verification was completed for this transaction, confirming the clients identity and source of funds in compliance with FinCEN BSA requirements.',
    `annual_income` DECIMAL(18,2) COMMENT 'Clients total annual income in USD at the time of the suitability review, as self-reported on the suitability questionnaire. Used to assess affordability of premiums and appropriateness of product.',
    `client_acknowledgment_date` DATE COMMENT 'The date on which the client signed or electronically acknowledged the suitability questionnaire and disclosure documents.',
    `client_acknowledgment_flag` BOOLEAN COMMENT 'Indicates whether the client has signed or electronically acknowledged the suitability questionnaire and associated disclosures, confirming the accuracy of the financial profile information provided.',
    `client_age` STRING COMMENT 'Age of the policyholder in whole years at the time of the suitability review. Critical factor in determining product appropriateness, particularly for annuity surrender periods relative to life expectancy.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this suitability review record was first created in the system, used for audit trail and SOX compliance tracking.',
    `determination_rationale` STRING COMMENT 'Narrative explanation provided by the agent or compliance reviewer documenting the basis for the suitability determination, including how the product aligns with the clients financial profile, objectives, and risk tolerance.',
    `disclosure_provided_flag` BOOLEAN COMMENT 'Indicates whether all required regulatory disclosures (e.g., NAIC Buyers Guide, product prospectus for variable products, fee disclosure) were provided to the client prior to or at the time of sale.',
    `existing_insurance_coverage` BOOLEAN COMMENT 'Indicates whether the client has existing life insurance or annuity coverage at the time of the suitability review, relevant for replacement analysis and concentration assessment.',
    `finra_reg_bi_applicable_flag` BOOLEAN COMMENT 'Indicates whether SEC Regulation Best Interest (Reg BI) applies to this transaction, typically for variable product sales through registered broker-dealers.',
    `investment_amount` DECIMAL(18,2) COMMENT 'The premium or investment amount in USD placed into the recommended product at the time of sale. Used to assess concentration risk relative to the clients total liquid net worth.',
    `investment_objective` STRING COMMENT 'Clients primary investment objective as stated on the suitability questionnaire. Drives product recommendation alignment analysis.. Valid values are `income|growth|preservation|tax_deferral|legacy`',
    `investment_time_horizon` STRING COMMENT 'Clients stated investment time horizon: short_term (under 3 years), medium_term (3–10 years), long_term (over 10 years). Must be compatible with product surrender charge period.. Valid values are `short_term|medium_term|long_term`',
    `is_1035_exchange` BOOLEAN COMMENT 'Indicates whether the transaction involves a tax-free 1035 exchange of an existing insurance or annuity contract, requiring additional suitability analysis of surrender charges, tax implications, and benefit comparisons.',
    `is_replacement` BOOLEAN COMMENT 'Indicates whether this sale involves the replacement of an existing life insurance policy or annuity contract, triggering additional disclosure and suitability requirements under NAIC Model Regulation #613.',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter US state code of the jurisdiction in which the sale transaction occurred, determining applicable state DOI suitability rules and disclosure requirements.. Valid values are `^[A-Z]{2}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this suitability review record was most recently modified, supporting audit trail requirements and change tracking for regulatory examination purposes.',
    `liquid_net_worth` DECIMAL(18,2) COMMENT 'Clients liquid net worth in USD (readily accessible assets excluding illiquid holdings such as real estate and retirement accounts) at the time of review. Critical for assessing ability to meet surrender charges and liquidity needs.',
    `net_worth` DECIMAL(18,2) COMMENT 'Clients total net worth in USD (assets minus liabilities) at the time of the suitability review, as self-reported. Used to evaluate financial capacity and product suitability relative to overall wealth.',
    `override_flag` BOOLEAN COMMENT 'Indicates whether the client elected to proceed with the transaction despite a not_suitable or conditionally_suitable determination, exercising their right to override the recommendation. Requires documented client acknowledgment.',
    `override_reason` STRING COMMENT 'Documented reason provided by the client for proceeding with the transaction despite a non-suitable or conditional determination. Required when override_flag is True.',
    `product_type` STRING COMMENT 'The type of insurance or annuity product recommended. Uses industry-standard abbreviations: FIA (Fixed Indexed Annuity), VUL (Variable Universal Life), UL (Universal Life), WL (Whole Life), IUL (Indexed Universal Life), SPIA (Single Premium Immediate Annuity), DI (Disability Income), LTC (Long-Term Care), term (Term Life). [ENUM-REF-CANDIDATE: FIA|VUL|UL|WL|IUL|SPIA|DI|LTC|term|GMWB|GMIB|GMAB — promote to reference product]',
    `regulatory_framework` STRING COMMENT 'The primary regulatory framework governing this suitability review. NAIC_275 for annuity suitability; DOL_ERISA for employer-sponsored plan sales; SEC_FINRA for variable product sales; STATE_DOI for state-specific requirements; BEST_INTEREST for Reg BI compliance.. Valid values are `NAIC_275|DOL_ERISA|SEC_FINRA|STATE_DOI|BEST_INTEREST`',
    `remediation_due_date` DATE COMMENT 'The deadline by which required remediation actions must be completed. Populated when remediation_required_flag is True.',
    `remediation_required_flag` BOOLEAN COMMENT 'Indicates whether a compliance remediation action is required as a result of this suitability review, such as policy rescission, refund, or corrective disclosure.',
    `review_date` DATE COMMENT 'The calendar date on which the suitability review was conducted, corresponding to the point-of-sale (POS) transaction date.',
    `review_reference_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to this suitability review at initiation, used for correspondence, audit trails, and regulatory filings. Format: SR-YYYY-NNNNNN.. Valid values are `^SR-[0-9]{4}-[0-9]{6}$`',
    `review_status` STRING COMMENT 'Current workflow status of the suitability review. suitable indicates the product is appropriate for the client; not_suitable triggers mandatory remediation; needs_review requires supervisory escalation; escalated indicates referral to compliance; withdrawn indicates the transaction was cancelled.. Valid values are `pending|suitable|not_suitable|needs_review|escalated|withdrawn`',
    `review_type` STRING COMMENT 'Classification of the review type. initial for new sales; replacement for policy replacements per NAIC Model #613; exchange for 1035 tax-free exchanges; periodic for ongoing best-interest reviews; supervisory for principal-level reviews.. Valid values are `initial|replacement|exchange|periodic|supervisory`',
    `risk_tolerance` STRING COMMENT 'Clients self-reported investment risk tolerance as captured on the suitability questionnaire. Determines appropriate product risk profile alignment.. Valid values are `conservative|moderate|moderately_aggressive|aggressive`',
    `source_of_funds` STRING COMMENT 'The origin of the funds used to purchase the product. Required for AML/BSA compliance and suitability analysis. [ENUM-REF-CANDIDATE: savings|retirement_account|inheritance|proceeds_from_sale|existing_policy|business_income|gift|other — promote to reference product]. Valid values are `savings|retirement_account|inheritance|proceeds_from_sale|existing_policy|other`',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this suitability review record originated (e.g., CRM for Salesforce Financial Services Cloud, POLICY_ADMIN for Policy Administration System, COMPLIANCE_WB for compliance workbench).. Valid values are `CRM|POLICY_ADMIN|UNDERWRITING|ANNUITY_ADMIN|COMPLIANCE_WB`',
    `suitability_determination` STRING COMMENT 'The formal suitability determination made by the reviewing agent: suitable confirms the product meets the clients needs; not_suitable prohibits the sale; conditionally_suitable requires additional disclosures or client acknowledgment.. Valid values are `suitable|not_suitable|conditionally_suitable`',
    `supervisory_notes` STRING COMMENT 'Free-text notes entered by the supervising principal documenting the basis for the supervisory review outcome, including any conditions, concerns, or required follow-up actions.',
    `supervisory_review_date` DATE COMMENT 'The date on which the supervisory or principal review of the suitability determination was completed.',
    `supervisory_review_outcome` STRING COMMENT 'The outcome of the principal or supervisory compliance review of the suitability determination. approved confirms the sale may proceed; rejected halts the transaction; returned_for_revision requires agent to update the analysis; escalated refers to senior compliance.. Valid values are `approved|rejected|returned_for_revision|escalated`',
    `tax_status` STRING COMMENT 'Tax qualification status of the funds used to purchase the product. qualified indicates pre-tax retirement funds (IRA, 401k); non_qualified indicates after-tax funds; roth indicates Roth IRA funds. Affects IRC Section 72 tax treatment and suitability of tax-deferred products.. Valid values are `qualified|non_qualified|roth|unknown`',
    `variable_product_flag` BOOLEAN COMMENT 'Indicates whether the recommended product is a variable insurance or annuity product (e.g., VUL, variable annuity), triggering additional SEC/FINRA oversight, prospectus delivery, and suitability requirements.',
    CONSTRAINT pk_suitability_review PRIMARY KEY(`suitability_review_id`)
) COMMENT 'Record of suitability and best-interest review conducted for annuity and life insurance sales transactions per NAIC Suitability in Annuity Transactions Model Regulation (#275) and DOL fiduciary standards. Captures policyholder financial profile at time of sale, product recommended, suitability determination (suitable, not suitable, needs review), reviewing agent, supervisory review outcome, and any required disclosures provided. Critical for FINRA and SEC oversight of variable product sales.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`aml_case` (
    `aml_case_id` BIGINT COMMENT 'Unique system-generated identifier for the AML/BSA investigation case record. Primary key for this entity.',
    `agency_id` BIGINT COMMENT 'Foreign key linking to agent.agency. Business justification: AML investigations may reveal agency-level patterns: multiple producers within same agency involved in premium financing schemes, STOLI rings, or structured transactions. Agency context is critical fo',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: AML investigation programs have dedicated compliance cost centers. Investigation costs, external counsel fees, and FinCEN filing costs must be allocated to cost centers for BSA/AML program expense rep',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: AML cases require documented investigation evidence, transaction records, and narrative support for SAR filings. Essential for AML case management, FinCEN reporting, and regulatory examination defense',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: AML cases resulting in asset seizure, restitution payments, or regulatory penalties generate journal entries. Finance must track financial impact of AML cases for regulatory reporting and financial st',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: AML cases are investigated and SAR filings made by specific legal entities. FinCEN filing requirement is entity-specific - each entity must have own AML program and file own SARs.',
    `party_id` BIGINT COMMENT 'Reference to the policyholder record associated with this AML/BSA case, when the subject is a policyholder or the suspicious activity is linked to a specific policy contract.',
    `plan_id` BIGINT COMMENT 'Foreign key linking to product.plan. Business justification: AML cases in life insurance are triggered by suspicious transactions on specific insurance plans (e.g., single-premium whole life used for structuring). FinCEN and ACLI guidance requires product-level',
    `producer_id` BIGINT COMMENT 'Reference to the licensed agent or broker associated with this AML/BSA case, when the subject or a contributing party is an agent. Used for producer conduct investigations and STOLI case tracking.',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: AML/BSA cases are governed by specific regulatory obligations (BSA Section 314(a)/(b), FinCEN CDD Rule, OFAC compliance). Adding regulatory_obligation_id to aml_case normalizes the governing regulator',
    `trade_id` BIGINT COMMENT 'Foreign key linking to investment.trade. Business justification: AML cases investigate suspicious trading activity (premium financing, STOLI indicators, rapid surrenders, unusual investment patterns). Real business process: suspicious activity investigation, SAR fi',
    `activity_end_date` DATE COMMENT 'Latest date of the suspicious activity or transaction pattern under investigation. Together with activity_start_date, defines the full activity period reported on FinCEN SAR filings.',
    `activity_start_date` DATE COMMENT 'Earliest date of the suspicious activity or transaction pattern under investigation. Used to define the activity period reported on FinCEN SAR filings and to scope the investigation lookback window.',
    `case_closed_timestamp` TIMESTAMP COMMENT 'Date and time when the AML/BSA investigation case was formally closed, either after FinCEN filing, no-filing determination, or referral to law enforcement. Null for open or in-progress cases.',
    `case_number` STRING COMMENT 'Externally-known, human-readable business identifier for the AML/BSA case, used in correspondence, FinCEN filings, and regulatory communications. Format: AML-YYYY-NNNNNN.. Valid values are `^AML-[0-9]{4}-[0-9]{6}$`',
    `case_opened_timestamp` TIMESTAMP COMMENT 'Date and time when the AML/BSA investigation case was formally opened and entered into the case management system. This is the principal business event timestamp for the case lifecycle and is used to calculate FinCEN filing deadline compliance (SAR must be filed within 30 days of detection).',
    `case_priority` STRING COMMENT 'Risk-based priority level assigned to the case, driving investigator workload management and escalation timelines. CRITICAL cases typically involve OFAC hits or law enforcement referrals.. Valid values are `LOW|MEDIUM|HIGH|CRITICAL`',
    `case_status` STRING COMMENT 'Current workflow lifecycle status of the AML/BSA investigation case. OPEN = newly initiated; UNDER_REVIEW = active investigation in progress; PENDING_FILING = investigation complete, awaiting FinCEN submission; FILED = SAR/CTR submitted to FinCEN; CLOSED = case resolved with no filing or post-filing closure; ESCALATED = referred to law enforcement or senior compliance.. Valid values are `OPEN|UNDER_REVIEW|PENDING_FILING|FILED|CLOSED|ESCALATED`',
    `case_type` STRING COMMENT 'Classification of the AML/BSA investigation case by regulatory obligation or suspicious activity pattern. SAR = Suspicious Activity Report; CTR = Currency Transaction Report; STRUCTURING = deliberate transaction structuring to evade reporting thresholds; STOLI = Stranger-Originated Life Insurance fraud; OFAC = Office of Foreign Assets Control screening hit; KYC_REMEDIATION = Know Your Customer remediation case. [ENUM-REF-CANDIDATE: SAR|CTR|STRUCTURING|STOLI|OFAC|KYC_REMEDIATION|OTHER — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when this AML case record was first created in the compliance case management system. Used for audit trail and data lineage tracking per SOX controls.',
    `detection_date` DATE COMMENT 'Calendar date on which the suspicious activity or transaction was first detected or identified, which may precede the formal case opening date. Critical for calculating the 30-day SAR filing deadline from the date of initial detection per FinCEN requirements.',
    `disposition` STRING COMMENT 'Final or current disposition outcome of the AML/BSA investigation case. SAR_FILED = Suspicious Activity Report submitted to FinCEN; CTR_FILED = Currency Transaction Report submitted; NO_ACTION = investigation concluded with no suspicious activity confirmed; LAW_ENFORCEMENT_REFERRED = case escalated to law enforcement; POLICY_TERMINATED = associated policy cancelled due to AML findings; CLAIM_DENIED = associated claim denied due to AML findings; PENDING = disposition not yet determined. [ENUM-REF-CANDIDATE: SAR_FILED|CTR_FILED|NO_ACTION|LAW_ENFORCEMENT_REFERRED|POLICY_TERMINATED|CLAIM_DENIED|PENDING — 7 candidates stripped; promote to reference product]',
    `disposition_notes` STRING COMMENT 'Free-text narrative documenting the rationale for the case disposition, investigative findings summary, and any actions taken. Required for regulatory examination evidence and internal audit trail. Subject to SAR confidentiality provisions — must not be disclosed to the subject.',
    `fincen_filed_date` DATE COMMENT 'Date on which the SAR or CTR was successfully submitted to FinCEN via the BSA E-Filing System. Used to verify compliance with the 30-day (or 60-day) SAR filing deadline and for regulatory examination evidence.',
    `fincen_filing_type` STRING COMMENT 'Type of regulatory report filed with FinCEN as a result of this AML/BSA case. SAR = Suspicious Activity Report (FinCEN Form 111); CTR = Currency Transaction Report (FinCEN Form 112); FBAR = Foreign Bank Account Report; NONE = case closed with no filing required after investigation.. Valid values are `SAR|CTR|FBAR|NONE`',
    `fincen_reference_number` STRING COMMENT 'Confirmation reference number assigned by FinCEN upon successful submission of a SAR or CTR filing. Used to track filing status, respond to law enforcement requests, and demonstrate regulatory compliance. Null until filing is submitted and acknowledged.',
    `initiation_source` STRING COMMENT 'Origin channel that triggered the creation of this AML/BSA case. AUTOMATED_ALERT = transaction monitoring system rule fired; MANUAL_REFERRAL = compliance officer or business unit referral; LAW_ENFORCEMENT = subpoena or law enforcement request; REGULATORY_EXAM = identified during state DOI or FinCEN examination; INTERNAL_AUDIT = identified during SOX or internal audit review; AGENT_REFERRAL = agent or broker flagged suspicious activity.. Valid values are `AUTOMATED_ALERT|MANUAL_REFERRAL|LAW_ENFORCEMENT|REGULATORY_EXAM|INTERNAL_AUDIT|AGENT_REFERRAL`',
    `jurisdiction` STRING COMMENT 'Two or three-letter code identifying the primary regulatory jurisdiction governing this AML case (e.g., US state code or federal jurisdiction code). Determines applicable state DOI reporting requirements and law enforcement referral protocols.. Valid values are `^[A-Z]{2,3}$`',
    `kyc_review_required` BOOLEAN COMMENT 'Indicates whether this AML case has triggered a mandatory KYC enhanced due diligence (EDD) review for the subject policyholder or agent. True = KYC/EDD review required; False = standard KYC sufficient.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent modification to this AML case record. Supports audit trail requirements and change tracking for regulatory examination purposes.',
    `law_enforcement_agency` STRING COMMENT 'Name of the law enforcement agency to which this case was referred, if applicable (e.g., FBI, DEA, IRS-CI, State Attorney General). Null when law_enforcement_referral is False.',
    `law_enforcement_referral` BOOLEAN COMMENT 'Indicates whether this AML/BSA case has been referred to law enforcement agencies (e.g., FBI, DEA, IRS Criminal Investigation, state law enforcement). True = referral made; False = no referral.',
    `ofac_match_reference` STRING COMMENT 'Reference identifier or SDN entry name from the OFAC screening system when a potential or confirmed match is identified. Used for escalation documentation and regulatory reporting. Null when screening status is CLEAR or NOT_SCREENED.',
    `ofac_screening_status` STRING COMMENT 'Result of OFAC Specially Designated Nationals (SDN) and sanctions list screening for the case subject. CONFIRMED_MATCH requires immediate case escalation and potential transaction blocking per OFAC compliance obligations.. Valid values are `NOT_SCREENED|CLEAR|POTENTIAL_MATCH|CONFIRMED_MATCH|FALSE_POSITIVE`',
    `risk_score` DECIMAL(18,2) COMMENT 'Quantitative risk score assigned to this AML case by the transaction monitoring system or compliance analyst, typically on a scale of 0-100. Higher scores indicate greater money laundering risk and drive case prioritization. Used for risk-based AML program management.',
    `sar_confidentiality_flag` BOOLEAN COMMENT 'Indicates whether this case is subject to SAR confidentiality provisions under the BSA, prohibiting disclosure of the SAR filing or its existence to the subject of the report. True = SAR filed and confidentiality applies; False = no SAR filed or confidentiality not applicable.',
    `sar_filing_deadline` DATE COMMENT 'Regulatory deadline by which the SAR must be submitted to FinCEN, calculated as 30 days from the detection date (or 60 days if no subject is identified). Drives compliance SLA monitoring and escalation workflows.',
    `subject_date_of_birth` DATE COMMENT 'Date of birth of the individual subject under investigation, required for identity verification, OFAC screening, and FinCEN SAR filing. Null for entity (non-individual) subjects.',
    `subject_name` STRING COMMENT 'Full legal name of the primary individual or entity under investigation in this AML/BSA case, as reported on FinCEN SAR/CTR filings. Required for regulatory filing and OFAC screening.',
    `subject_tax_number` STRING COMMENT 'Social Security Number (SSN) or Employer Identification Number (EIN) / Taxpayer Identification Number (TIN) of the AML case subject, used for FinCEN SAR/CTR filing and OFAC screening. Stored encrypted per HIPAA and IRS data security requirements.',
    `subject_type` STRING COMMENT 'Classification of the primary subject under investigation. Identifies whether the suspicious activity is associated with a policyholder, licensed agent/broker, policy beneficiary, unrelated third party, or a legal entity (trust, corporation).. Valid values are `POLICYHOLDER|AGENT|BENEFICIARY|THIRD_PARTY|ENTITY`',
    `suspicious_activity_type` STRING COMMENT 'Specific category of suspicious activity identified in the investigation, aligned with FinCEN SAR activity type classifications. Examples include: CASH_TRANSACTION, STRUCTURING, MONEY_LAUNDERING, FRAUD, TERRORIST_FINANCING, INSURANCE_FRAUD, STOLI, IDENTITY_THEFT, ELDER_FINANCIAL_ABUSE. [ENUM-REF-CANDIDATE: CASH_TRANSACTION|STRUCTURING|MONEY_LAUNDERING|FRAUD|TERRORIST_FINANCING|INSURANCE_FRAUD|STOLI|IDENTITY_THEFT|ELDER_FINANCIAL_ABUSE — promote to reference product]',
    `transaction_amount` DECIMAL(18,2) COMMENT 'Total dollar amount of the suspicious transaction(s) under investigation. For CTR cases, this is the cash transaction amount exceeding the $10,000 reporting threshold. For SAR cases, this is the aggregate amount of suspicious activity. Reported on FinCEN filings.',
    `transaction_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the suspicious transaction amount. Typically USD for domestic cases; foreign currency cases may indicate additional money laundering risk.. Valid values are `^[A-Z]{3}$`',
    CONSTRAINT pk_aml_case PRIMARY KEY(`aml_case_id`)
) COMMENT 'Operational record of an Anti-Money Laundering (AML) or Bank Secrecy Act (BSA) investigation case initiated by automated transaction monitoring alerts or manual referrals. Captures case type (SAR, CTR, structuring, STOLI), subject policyholder or agent, triggering transaction details, case status (open, under review, filed, closed), assigned investigator, FinCEN filing reference, and disposition. Supports FinCEN SAR/CTR filing obligations and OFAC screening outcomes.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`privacy_incident` (
    `privacy_incident_id` BIGINT COMMENT 'Unique system-generated identifier for the privacy incident record. Primary key for this entity.',
    `agency_id` BIGINT COMMENT 'Foreign key linking to agent.agency. Business justification: Privacy incidents can originate from agency-level data handling failures (agency staff accessing or exposing policyholder PHI/PII). Linking privacy_incident to agency enables breach investigation, age',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: HIPAA breach remediation, individual notification, and legal response costs must be allocated to cost centers for financial tracking and regulatory expense reporting. Insurance companies track privacy',
    `exam_finding_id` BIGINT COMMENT 'Foreign key linking to compliance.exam_finding. Business justification: A privacy incident may be identified through a specific exam finding (e.g., an examiner identifies improper PHI handling during a market conduct exam). Adding exam_finding_id to privacy_incident estab',
    `in_force_policy_id` BIGINT COMMENT 'Foreign key linking to policy.in_force_policy. Business justification: Privacy incidents often involve specific policy records (e.g., unauthorized access, data breach). Linking enables tracking which policies were affected, supports breach notification requirements under',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Privacy incidents generate incident reports, breach notification letters, HHS notifications, and remediation documentation required by HIPAA and state breach laws. Critical for breach response workflo',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Privacy breaches result in penalties, legal costs, notification costs, credit monitoring expenses that must be journalized. Finance needs to track actual financial impact for reserve adequacy and disc',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Privacy incidents are reported by the legal entity responsible for the data. HIPAA and state breach notification laws require entity-specific reporting and accountability.',
    `market_conduct_exam_id` BIGINT COMMENT 'Foreign key linking to compliance.market_conduct_exam. Business justification: Privacy incidents may be identified during a market conduct examination (e.g., DOI examination of data handling practices). Adding market_conduct_exam_id to privacy_incident enables tracking of exam-i',
    `mib_inquiry_id` BIGINT COMMENT 'Foreign key linking to underwriting.mib_inquiry. Business justification: MIB inquiries involve consumer report data; unauthorized access or disclosure triggers privacy incident reporting. FCRA/privacy requirement: breach tracking for MIB data. Links privacy incident to spe',
    `template_id` BIGINT COMMENT 'Foreign key linking to document.template. Business justification: HIPAA and state breach notification laws require specific notification letter templates for affected individuals, HHS, and state AGs. Privacy incident response teams must track which approved notifica',
    `paramedical_exam_id` BIGINT COMMENT 'Foreign key linking to underwriting.paramedical_exam. Business justification: Paramedical exam results contain PHI; breaches (lost specimens, unauthorized access to lab results) require incident tracking. HIPAA requirement: breach notification for medical examination data. Link',
    `party_id` BIGINT COMMENT 'Reference to the primary policyholder whose Protected Health Information (PHI) or Personally Identifiable Information (PII) was involved in the incident. Links to the policyholder master record.',
    `producer_id` BIGINT COMMENT 'Foreign key linking to agent.producer. Business justification: Privacy incidents often involve producer actions: unauthorized PHI access, lost/stolen devices with customer data, email breaches. HIPAA breach investigations require tracking which producer caused or',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: HIPAA privacy incidents are governed by specific regulatory obligations (HIPAA Privacy Rule, HITECH Act, state breach notification laws). Adding regulatory_obligation_id to privacy_incident normalizes',
    `state_regulation_id` BIGINT COMMENT 'Foreign key linking to compliance.state_regulation. Business justification: Privacy incidents trigger state-specific breach notification obligations that vary by jurisdiction. Adding state_regulation_id to privacy_incident normalizes the governing state regulation, enabling s',
    `aps_record_id` BIGINT COMMENT 'Foreign key linking to underwriting.aps_record. Business justification: APS records contain highly sensitive PHI; breaches involving APS documents (lost records, unauthorized disclosure) must be tracked. HIPAA requirement: breach notification for attending physician state',
    `application_id` BIGINT COMMENT 'Foreign key linking to underwriting.application. Business justification: Privacy breaches during underwriting (unauthorized PHI access, lost medical records) must be tracked against the application. HIPAA requirement: breach notification tied to affected individuals appli',
    `affected_individuals_count` STRING COMMENT 'Number of individuals whose PHI or PII was involved in the privacy incident. Determines notification thresholds: incidents affecting 500+ individuals in a state require immediate HHS OCR notification; 500+ total triggers media notification.',
    `breach_determination_date` DATE COMMENT 'Date on which the formal breach determination was made following completion of the four-factor risk assessment. Relevant for calculating notification deadlines under HIPAA and state breach notification laws.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when the privacy incident record was first created in the compliance management system. Supports audit trail and data lineage requirements.',
    `data_format` STRING COMMENT 'Format of the data involved in the privacy incident — electronic (digital files, databases, emails), paper (physical documents), verbal (oral disclosure), or mixed. Influences remediation approach and risk assessment scoring.. Valid values are `electronic|paper|verbal|mixed`',
    `discovery_date` DATE COMMENT 'The date on which the covered entity or business associate first became aware of the potential privacy incident. Starts the 60-day HIPAA breach notification clock under 45 CFR § 164.412.',
    `doi_notification_date` DATE COMMENT 'Date on which notification was submitted to the State Department of Insurance. Under the NAIC model law, notification is generally required within 72 hours of determining a cybersecurity event.',
    `doi_notification_required` BOOLEAN COMMENT 'Indicates whether notification to the State Department of Insurance is required under the NAIC Insurance Data Security Model Law or state-specific insurance data security regulations.',
    `hhs_notification_date` DATE COMMENT 'Date on which notification was submitted to HHS OCR via the breach reporting portal. Must occur within 60 days of discovery for breaches affecting 500+ individuals, or by March 1 of the following year for smaller breaches.',
    `hhs_notification_required` BOOLEAN COMMENT 'Indicates whether notification to the U.S. Department of Health and Human Services Office for Civil Rights (HHS OCR) is required. True for all confirmed HIPAA breaches; breaches affecting 500+ individuals require immediate notification, others are reported annually.',
    `incident_date` DATE COMMENT 'The date on which the privacy incident actually occurred or is estimated to have begun. May differ from discovery_date when incidents are discovered after the fact. Required for HHS OCR annual breach report.',
    `incident_description` STRING COMMENT 'Detailed narrative description of the privacy incident — what happened, how it was discovered, what data was involved, and the circumstances of the unauthorized access or disclosure. Core documentation for regulatory submissions and internal investigations.',
    `incident_end_date` DATE COMMENT 'The date on which the privacy incident ceased or was contained. Used to calculate exposure duration and assess scope of harm for breach risk assessment.',
    `incident_location` STRING COMMENT 'Physical or logical location where the privacy incident occurred (e.g., home office, branch office name, cloud environment, third-party vendor site). Used for root cause analysis and remediation targeting.',
    `incident_reference_number` STRING COMMENT 'Human-readable, externally referenceable identifier assigned to the privacy incident at intake (e.g., PI-2024-000123). Used in regulatory correspondence, HHS OCR submissions, and state AG notifications.. Valid values are `^PI-[0-9]{4}-[0-9]{6}$`',
    `incident_status` STRING COMMENT 'Current workflow state of the privacy incident through its lifecycle — from initial intake through investigation, breach determination, notification, and closure. [ENUM-REF-CANDIDATE: open|under_investigation|breach_confirmed|no_breach_determined|notified|closed|reopened — promote to reference product]',
    `incident_type` STRING COMMENT 'Classification of the nature of the privacy incident as defined by HHS OCR breach reporting categories. Drives notification obligations and remediation workflows. [ENUM-REF-CANDIDATE: unauthorized_access|unauthorized_disclosure|lost_device|stolen_device|hacking_it_incident|improper_disposal|mailing_error|other — promote to reference product]',
    `includes_financial_account` BOOLEAN COMMENT 'Indicates whether financial account numbers, payment card data, or banking information were among the data elements exposed. Triggers PCI DSS notification obligations and heightened state breach law requirements.',
    `includes_health_information` BOOLEAN COMMENT 'Indicates whether Protected Health Information (PHI) as defined under HIPAA was among the data elements exposed. Determines applicability of HIPAA Breach Notification Rule and state health privacy laws.',
    `includes_ssn` BOOLEAN COMMENT 'Indicates whether Social Security Numbers (SSNs) were among the data elements exposed in the incident. SSN exposure triggers mandatory notification under virtually all 50 state data breach notification laws and heightens identity theft risk assessment.',
    `individual_notification_date` DATE COMMENT 'Date on which written notification was sent to affected individuals. Must occur within 60 days of discovery of a confirmed breach. Supports HIPAA compliance deadline tracking.',
    `individual_notification_required` BOOLEAN COMMENT 'Indicates whether written notification to affected individuals is required under the HIPAA Breach Notification Rule. Required for all confirmed breaches; must be sent within 60 days of discovery.',
    `involved_business_associate` BOOLEAN COMMENT 'Indicates whether a HIPAA Business Associate (BA) — such as a TPA, vendor, or service provider — was involved in or responsible for the privacy incident. Business associates have independent HIPAA breach notification obligations to the covered entity.',
    `is_breach_determined` BOOLEAN COMMENT 'Indicates whether the privacy incident has been formally determined to constitute a reportable breach under the HIPAA Breach Notification Rule following completion of the four-factor risk assessment. True = breach confirmed; False = not a breach (low probability of compromise).',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter US state code of the primary jurisdiction governing notification obligations for this incident. Determines which state data breach notification law applies and the applicable notification deadline.. Valid values are `^[A-Z]{2}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent modification to the privacy incident record. Supports audit trail integrity and change management tracking.',
    `media_notification_date` DATE COMMENT 'Date on which notification was provided to prominent media outlets in the affected state(s). Required within 60 days of discovery for breaches affecting 500+ residents of a state.',
    `media_notification_required` BOOLEAN COMMENT 'Indicates whether notification to prominent media outlets is required. Triggered when a confirmed breach affects 500 or more residents of a single state or jurisdiction.',
    `multi_state_flag` BOOLEAN COMMENT 'Indicates whether the incident involves affected individuals across multiple states, triggering notification obligations under multiple state data breach notification laws simultaneously.',
    `no_breach_rationale` STRING COMMENT 'Documented justification when the incident is determined NOT to constitute a reportable breach, referencing the four-factor risk assessment outcome (nature/extent of PHI, unauthorized person, whether PHI was actually acquired/viewed, extent of risk mitigation). Required for HIPAA documentation obligations.',
    `notification_deadline_date` DATE COMMENT 'Calculated deadline by which all required notifications (HHS OCR, individuals, media, state AG, DOI) must be completed. Derived from discovery_date plus the applicable regulatory notification window (e.g., 60 days under HIPAA, 30–72 hours under NAIC model law). Stored for deadline monitoring and escalation.',
    `phi_data_elements_exposed` STRING COMMENT 'Comma-delimited list of PHI or PII data element categories involved in the incident (e.g., name, SSN, date_of_birth, diagnosis, policy_number, financial_account, biometric). Required for HHS OCR breach report and state AG notifications. [ENUM-REF-CANDIDATE: name|ssn|date_of_birth|diagnosis|treatment|policy_number|financial_account|biometric|address|email|phone — promote to reference product]',
    `remediation_actions_taken` STRING COMMENT 'Narrative description of corrective and remediation actions taken in response to the privacy incident (e.g., system access revoked, encryption implemented, workforce retrained, BA agreement updated, policy revised). Required for HIPAA documentation and regulatory examination.',
    `remediation_completed_date` DATE COMMENT 'Date on which all remediation actions were confirmed as completed. Supports closure of the incident record and regulatory documentation of corrective action.',
    `remediation_due_date` DATE COMMENT 'Target date by which all remediation actions must be completed. Used for compliance tracking and escalation management.',
    `reported_timestamp` TIMESTAMP COMMENT 'Date and time the privacy incident was formally reported to the compliance or privacy office. Establishes the internal reporting timeline for SOX controls and HIPAA workforce training obligations.',
    `risk_assessment_score` STRING COMMENT 'Overall risk level determined by the four-factor HIPAA breach risk assessment: (1) nature and extent of PHI involved, (2) identity of unauthorized person, (3) whether PHI was actually acquired or viewed, (4) extent to which risk has been mitigated. Drives breach determination and notification decisions.. Valid values are `low|moderate|high|critical`',
    `root_cause_category` STRING COMMENT 'High-level categorization of the root cause of the privacy incident. Used for trend analysis, remediation prioritization, and regulatory reporting to HHS OCR and state DOIs. [ENUM-REF-CANDIDATE: human_error|malicious_insider|external_attack|system_failure|vendor_error|process_failure|other — promote to reference product]',
    `state_ag_notification_date` DATE COMMENT 'Date on which notification was submitted to the State Attorney General. Deadline varies by state (e.g., 30 days in some states, 60 days in others).',
    `state_ag_notification_required` BOOLEAN COMMENT 'Indicates whether notification to the State Attorney General is required under applicable state data breach notification law. Requirements vary by state.',
    CONSTRAINT pk_privacy_incident PRIMARY KEY(`privacy_incident_id`)
) COMMENT 'Record of a HIPAA privacy incident, data breach, or unauthorized disclosure of Protected Health Information (PHI) or Personally Identifiable Information (PII). Captures incident type, discovery date, affected individuals count, data elements exposed, breach determination (yes/no), notification obligations triggered (HHS, state AG, affected individuals), notification dates, and remediation actions taken. Supports HIPAA Breach Notification Rule compliance and state data breach law reporting.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`policy_form_approval` (
    `policy_form_approval_id` BIGINT COMMENT 'Unique surrogate identifier for each policy form or rate filing approval record. Primary key for the policy_form_approval data product.',
    `acord_form_id` BIGINT COMMENT 'Foreign key linking to document.acord_form. Business justification: Policy form approvals are filed for specific ACORD forms or company-proprietary forms. Linking policy_form_approval directly to acord_form enables compliance teams to determine which ACORD form versio',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Form filing costs (actuarial review, legal counsel, state filing fees) are tracked by product development cost center for product profitability analysis and budget management.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Form approvals require the actual policy form documents, rate manuals, actuarial certifications, and DOI approval letters. Essential for state form filing workflow and approved form library management',
    `form_id` BIGINT COMMENT 'Foreign key linking to product.form. Business justification: A policy_form_approval is the DOI regulatory approval of a specific product form. The compliance record must reference the product.form entity it approves. This is the most fundamental link in form fi',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Form approvals are entity-specific (each legal entity must file for approval in each jurisdiction where it operates). Fundamental regulatory filing requirement for product distribution.',
    `plan_id` BIGINT COMMENT 'Foreign key linking to product.product_plan. Business justification: Form approvals are state-specific approvals of product plans for sale in each jurisdiction. Each approval record ties to the plan being approved. Critical for determining which plans can be sold in wh',
    `plan_version_id` BIGINT COMMENT 'Foreign key linking to product.plan_version. Business justification: Form approvals are version-specific - when a plan version changes (benefits, rates, terms), new state approvals are required. More granular than plan-level linking. Essential for version control, stat',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Policy form approvals are regulatory filings that fulfill specific state DOI obligations. The obligation defines the filing type and requirements.',
    `rider_definition_id` BIGINT COMMENT 'Foreign key linking to product.rider_definition. Business justification: Rider forms require separate DOI form approvals in each state. A policy_form_approval covering a rider must reference the rider_definition it approves. This is standard DOI filing practice — rider app',
    `state_regulation_id` BIGINT COMMENT 'Foreign key linking to compliance.state_regulation. Business justification: Policy form approvals must comply with state-specific insurance regulations. The approval describes the filing, while the regulation describes the state-specific rules governing form approval.',
    `actuarial_justification_reference` STRING COMMENT 'Reference identifier for the actuarial memorandum or actuarial certification document that supports the rate filing, including loss ratio analysis, experience data, and rate adequacy demonstration. Required for rate filings per state DOI requirements.',
    `approval_date` DATE COMMENT 'The date on which the state DOI formally approved the form or rate filing. Null if the filing is pending, disapproved, or withdrawn.',
    `approval_status` STRING COMMENT 'Current lifecycle status of the form or rate filing with the state DOI. Drives whether the form or rate may be used in the jurisdiction. Deemed approved applies when the DOI has not acted within the statutory review period.. Valid values are `pending|approved|disapproved|withdrawn|deemed_approved|conditionally_approved`',
    `company_filing_reference` STRING COMMENT 'Internal company-assigned reference number used to track the filing within the companys compliance and policy administration systems, independent of the SERFF or DOI reference numbers.',
    `company_response_date` DATE COMMENT 'The date on which the company submitted its formal response to DOI objections or requests for additional information. Tracks responsiveness within the regulatory review cycle.',
    `conditional_approval_conditions` STRING COMMENT 'Description of conditions or modifications required by the DOI as part of a conditional approval. The company must satisfy these conditions before or concurrent with use of the form or rate. Populated only when approval_status is conditionally_approved.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this policy form approval record was first created in the compliance data product, capturing the initial data entry or system ingestion event.',
    `deemed_approved_date` DATE COMMENT 'The date on which the filing is deemed approved by operation of law because the DOI did not act within the statutory review period. Calculated as submission_date plus review_period_days. Null if the DOI acted before the deadline.',
    `disapproval_reason` STRING COMMENT 'The stated reason provided by the state DOI for disapproving the form or rate filing. Populated only when approval_status is disapproved. Used to guide remediation and refiling efforts.',
    `doi_approval_reference` STRING COMMENT 'The official approval reference number, certificate number, or acknowledgment identifier issued by the state Department of Insurance (DOI) upon approval of the filing. Used to evidence regulatory compliance during market conduct examinations.',
    `doi_objection_details` STRING COMMENT 'Narrative description of objections, deficiency letters, or requests for additional information issued by the state DOI during the review process. Captures the substance of regulatory concerns requiring company response.',
    `effective_date` DATE COMMENT 'The date on which the approved form or rate schedule becomes effective for use in new policy issuance or in-force policy administration within the jurisdiction. For rate filings, this is the proposed or approved rate effective date.',
    `expiration_date` DATE COMMENT 'The date on which the form or rate approval expires or is superseded, after which the form or rate may no longer be used for new business. Null for approvals with no defined expiration.',
    `filing_description` STRING COMMENT 'Narrative description of the purpose and scope of the filing, including key changes from prior versions, new product features, benefit modifications, or regulatory compliance updates driving the submission.',
    `filing_method` STRING COMMENT 'The regulatory filing method required by the jurisdiction for this form or rate filing. Prior approval requires DOI approval before use; file-and-use allows use upon filing; use-and-file allows use before filing; informational is for notice only.. Valid values are `prior_approval|file_and_use|use_and_file|informational`',
    `filing_owner` STRING COMMENT 'Name or identifier of the internal compliance officer, actuary, or product manager responsible for managing this filing through the regulatory approval process.',
    `filing_reference_number` STRING COMMENT 'Externally-known unique reference number assigned to the filing submission, as issued by the state Department of Insurance (DOI) or the companys internal filing tracking system (e.g., SERFF tracking number or company-assigned filing ID).',
    `irc_7702_compliant_flag` BOOLEAN COMMENT 'Indicates whether the filed policy form has been reviewed and confirmed to comply with IRC Section 7702 life insurance tax qualification requirements, including the Cash Value Accumulation Test (CVAT) or Guideline Premium Test (GPT). Critical for life insurance tax treatment.',
    `is_currently_approved` BOOLEAN COMMENT 'Indicates whether the form or rate is currently approved and authorized for use in the jurisdiction as of the current date. Derived from approval_status and effective/expiration dates; serves as the operational compliance gate for policy issuance systems.',
    `is_in_use` BOOLEAN COMMENT 'Indicates whether the form or rate schedule is actively being used in new business issuance or in-force policy administration within the jurisdiction. Distinguishes approved-but-not-deployed forms from actively deployed ones.',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter US state or territory code identifying the jurisdiction in which this form or rate filing was submitted to the Department of Insurance. Ensures only approved forms and rates are used in each specific jurisdiction.. Valid values are `^[A-Z]{2}$`',
    `ltc_rate_increase_percentage` DECIMAL(18,2) COMMENT 'For Long-Term Care (LTC) insurance rate increase filings, the specific percentage increase in LTC premiums requested from the DOI. Subject to heightened regulatory scrutiny and actuarial justification requirements under NAIC LTC model regulations.',
    `mec_test_type` STRING COMMENT 'Identifies the IRC Section 7702 compliance test methodology applied to the policy form: Cash Value Accumulation Test (CVAT) or Guideline Premium Test (GPT). Determines Modified Endowment Contract (MEC) status thresholds. Not applicable for annuity or non-life products.. Valid values are `cvat|gpt|not_applicable`',
    `naic_product_code` STRING COMMENT 'The NAIC standardized product code assigned to the insurance product type associated with this filing. Used for regulatory reporting, market conduct analysis, and cross-state filing coordination.',
    `outside_counsel_reference` STRING COMMENT 'Reference to the external legal counsel or regulatory affairs firm engaged to support the filing, if applicable. Used for complex or contested filings requiring specialized regulatory legal expertise.',
    `prior_form_number` STRING COMMENT 'The form number of the previously approved version that this filing supersedes or replaces. Enables traceability of form revision history and supports grandfathering analysis for in-force policies.',
    `product_line` STRING COMMENT 'The insurance product line to which the filed form or rate schedule applies (e.g., Term Life, Whole Life (WL), Universal Life (UL), Variable Universal Life (VUL), Annuity, Long-Term Care (LTC), Disability Income (DI), Group Life). [ENUM-REF-CANDIDATE: term_life|whole_life|universal_life|variable_life|indexed_universal_life|fixed_indexed_annuity|variable_annuity|ltc|disability_income|group_life|spia — promote to reference product]',
    `rate_change_percentage` DECIMAL(18,2) COMMENT 'For rate filings, the percentage change in premium rates proposed or approved relative to the current in-force rates. Positive values indicate a rate increase; negative values indicate a rate decrease. Null for form-only filings.',
    `rate_filing_type` STRING COMMENT 'For rate filings, classifies the nature of the rate action: new rate schedule introduction, revision to existing rates, Long-Term Care (LTC) rate increase filing, or withdrawal of a rate schedule. Null for pure form filings.. Valid values are `new_rate|rate_revision|ltc_rate_increase|rate_withdrawal`',
    `review_period_days` STRING COMMENT 'The statutory or regulatory maximum number of days the DOI has to review and act on the filing before it is deemed approved (for prior approval states). Varies by state and product line.',
    `sec_registration_number` STRING COMMENT 'For variable product filings, the SEC registration number (e.g., Form S-1, Form N-4 registration) associated with the product. Required for variable life and variable annuity products subject to SEC registration. Null for non-variable products.',
    `serff_tracking_number` STRING COMMENT 'The unique tracking number assigned by the NAICs System for Electronic Rate and Form Filing (SERFF) platform when the filing is submitted electronically. Primary cross-reference identifier for SERFF-based filings.',
    `submission_date` DATE COMMENT 'The date on which the form or rate filing was formally submitted to the state Department of Insurance. Marks the start of the regulatory review clock for prior approval filings.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this policy form approval record was most recently updated, reflecting any changes to filing status, approval dates, DOI responses, or other attributes.',
    `variable_product_flag` BOOLEAN COMMENT 'Indicates whether the filed form or rate applies to a variable insurance or annuity product subject to SEC and FINRA oversight in addition to state DOI regulation. Triggers additional compliance requirements for variable product filings.',
    `withdrawal_date` DATE COMMENT 'The date on which the company voluntarily withdrew the filing from DOI review. Populated only when approval_status is withdrawn.',
    CONSTRAINT pk_policy_form_approval PRIMARY KEY(`policy_form_approval_id`)
) COMMENT 'Master record of state DOI filings for policy forms, rider forms, endorsement forms, and premium rate schedules. For form filings: captures form number, form type (base policy, rider, endorsement, application), product line, filing method (prior approval, file-and-use, use-and-file), state, submission/approval dates, approval reference, and form status. For rate filings: captures filing type (new rate, rate revision, LTC rate increase), actuarial justification reference, proposed effective date, approval status, rate change percentage, and DOI response details. Ensures only approved forms and rates are used in each jurisdiction, supports state rate regulation compliance, and serves as the single source of truth for all form and rate approval status across all jurisdictions.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`rate_filing` (
    `rate_filing_id` BIGINT COMMENT 'Unique surrogate identifier for each rate filing record in the compliance domain. Primary key for the rate_filing data product.',
    `coi_rate_schedule_id` BIGINT COMMENT 'Foreign key linking to product.coi_rate_schedule. Business justification: COI rate schedule changes for in-force UL/IUL policies require state rate filings. The compliance rate_filing that approves a COI rate increase must reference the specific coi_rate_schedule it governs',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Rate filing preparation costs (actuarial analysis, regulatory filings, legal review) are significant and tracked by cost center for product line profitability and pricing adequacy analysis.',
    `ifrs17_contract_group_id` BIGINT COMMENT 'Foreign key linking to finance.ifrs17_contract_group. Business justification: Rate filings affect the profitability classification and CSM of IFRS17 contract groups. When rates change, the onerous contract assessment and CSM release pattern for the affected contract group must ',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Rate filings are made by specific legal entities in specific jurisdictions. Fundamental regulatory filing requirement - rates must be approved for each entity in each state.',
    `plan_id` BIGINT COMMENT 'Reference to the insurance product (e.g., term life, whole life, LTC, annuity) for which the rate filing is submitted. Links the filing to the specific product line subject to rate regulation.',
    `plan_version_id` BIGINT COMMENT 'Foreign key linking to product.plan_version. Business justification: Rate filings are version-specific regulatory submissions. Actuaries and state DOI filings reference the exact plan version whose rates are being changed. rate_filing already has plan_id but lacks plan',
    `policy_form_approval_id` BIGINT COMMENT 'Foreign key linking to compliance.policy_form_approval. Business justification: Rate filings reference specific approved policy forms (rate changes apply to approved form numbers). Links rate filing to the form approval for product launch coordination and regulatory compliance va',
    `premium_rate_table_id` BIGINT COMMENT 'Foreign key linking to product.premium_rate_table. Business justification: A compliance rate_filing is the regulatory approval that activates a new premium_rate_table. Actuarial and compliance teams must link the approved filing to the rate table it governs. This is the core',
    `rbc_calculation_id` BIGINT COMMENT 'Foreign key linking to finance.rbc_calculation. Business justification: Rate filings, particularly LTC rate increase filings, are directly tied to RBC calculations demonstrating capital adequacy supporting the rate change. Regulators require actuarial justification linkin',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Rate filings fulfill regulatory obligations for premium rate approval. The obligation defines the filing type and jurisdiction requirements.',
    `state_regulation_id` BIGINT COMMENT 'Foreign key linking to compliance.state_regulation. Business justification: Rate filings must comply with state-specific rate filing regulations. The filing describes the submission, while the regulation describes the state-specific rules governing rate approval.',
    `affected_policy_count` STRING COMMENT 'Number of in-force policies in the filing jurisdiction that will be affected by the proposed rate change. Required for LTC rate increase filings and used by the DOI to assess consumer impact. Derived from policy administration system counts at time of filing.',
    `annual_premium_impact_amount` DECIMAL(18,2) COMMENT 'Estimated total annual premium impact (in USD) of the proposed rate change across all affected in-force policies in the filing jurisdiction. Used by the DOI to assess the financial impact on policyholders and by the company for financial planning.',
    `approved_effective_date` DATE COMMENT 'Date on which the DOI-approved rates become effective for use. May differ from the proposed effective date if the DOI modifies the requested effective date as a condition of approval. Null until the filing reaches approved status.',
    `approved_rate_change_percentage` DECIMAL(18,2) COMMENT 'The rate change percentage as finally approved by the state DOI, which may differ from the originally proposed rate_change_percentage if the DOI required modifications as a condition of approval. Null until the filing is approved.',
    `certifying_actuary_credential` STRING COMMENT 'Professional actuarial credential of the certifying actuary (e.g., FSA — Fellow of the Society of Actuaries, MAAA — Member of the American Academy of Actuaries). Validates the actuarys qualification to certify the rate filing.. Valid values are `FSA|MAAA|FSA_MAAA|ASA|FCAS`',
    `certifying_actuary_name` STRING COMMENT 'Full name of the qualified actuary (Fellow of the Society of Actuaries or equivalent) who certified the actuarial memorandum and rate justification supporting this filing. Required by most state DOIs as part of the rate filing package.',
    `consumer_notice_required_flag` BOOLEAN COMMENT 'Indicates whether the rate filing requires individual policyholder notification of the rate change (e.g., LTC rate increases, in-force rate revisions). Triggers the consumer notification workflow in the policy administration system.',
    `consumer_notice_sent_date` DATE COMMENT 'Date on which policyholder notification letters were sent for the rate change. Required for LTC rate increases and other in-force rate revisions requiring consumer notice. Null if consumer_notice_required_flag is false.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the rate filing record was first created in the compliance system. Supports audit trail requirements and data lineage tracking.',
    `disapproval_date` DATE COMMENT 'Date on which the state Department of Insurance (DOI) formally disapproved the rate filing. Null for filings that are approved, pending, or withdrawn. Triggers the companys obligation to respond or refile.',
    `disapproval_reason` STRING COMMENT 'Narrative description of the state DOIs stated reason(s) for disapproving the rate filing. Null for approved or pending filings. Used to guide refiling strategy and actuarial revisions.',
    `doi_approval_date` DATE COMMENT 'Date on which the state Department of Insurance (DOI) formally approved the rate filing. Null for filings that are pending, disapproved, or withdrawn. Distinct from the approved effective date, which is when rates go into use.',
    `doi_objection_count` STRING COMMENT 'Number of formal objections or deficiency letters issued by the state DOI during the review of this rate filing. Each objection requires a company response and may extend the review timeline. Tracks regulatory engagement complexity.',
    `doi_objection_response_date` DATE COMMENT 'Date on which the company submitted its response to the DOIs most recent objection or deficiency letter. Used to track compliance with DOI response deadlines and filing timeline management.',
    `doi_objection_response_due_date` DATE COMMENT 'Due date for the companys response to the most recent DOI objection or deficiency letter. Failure to respond by this date may result in automatic disapproval or withdrawal of the filing.',
    `experience_period_end_date` DATE COMMENT 'End date of the actuarial experience period used to develop the loss ratios, claim costs, and other actuarial assumptions supporting the rate filing. Together with the start date, defines the historical data window underlying the actuarial justification.',
    `experience_period_start_date` DATE COMMENT 'Start date of the actuarial experience period used to develop the loss ratios, claim costs, and other actuarial assumptions supporting the rate filing. Defines the historical data window underlying the actuarial justification.',
    `external_counsel_reference` STRING COMMENT 'Reference identifier or name of external legal counsel engaged to support the rate filing, if applicable. Relevant for contested filings, LTC rate increase hearings, or filings requiring regulatory negotiation.',
    `filing_description` STRING COMMENT 'Narrative description of the rate filing, summarizing the nature of the rate change, the affected policy forms, the actuarial basis, and any special circumstances (e.g., LTC rate stabilization, experience deterioration, regulatory mandate). Used for internal compliance tracking and DOI correspondence.',
    `filing_method` STRING COMMENT 'Regulatory filing method required by the state for this rate filing. Prior approval requires DOI approval before use; file-and-use allows immediate use upon filing; use-and-file requires filing after use; no-filing-required states are exempt. Determines the compliance timeline and approval workflow.. Valid values are `prior_approval|file_and_use|use_and_file|no_filing_required|informational`',
    `filing_number` STRING COMMENT 'Externally-known unique reference number assigned to the rate filing, typically generated by the company or the state DOI system (e.g., SERFF tracking number or company-assigned filing reference). Used for cross-referencing with state DOI portals and internal compliance tracking.',
    `filing_preparer_name` STRING COMMENT 'Name of the internal compliance or actuarial staff member responsible for preparing and submitting the rate filing. Used for accountability tracking and DOI correspondence.',
    `filing_status` STRING COMMENT 'Current lifecycle status of the rate filing with the state DOI. Tracks the filing from initial draft through submission, regulatory review, and final disposition (approved, disapproved, or withdrawn). [ENUM-REF-CANDIDATE: draft|submitted|pending_review|approved|disapproved|withdrawn|conditionally_approved — promote to reference product]',
    `hearing_date` DATE COMMENT 'Scheduled or actual date of the DOI public or administrative hearing for this rate filing. Null if hearing_required_flag is false. Tracks the regulatory hearing calendar for compliance management.',
    `hearing_required_flag` BOOLEAN COMMENT 'Indicates whether the state DOI has required a public hearing or administrative hearing as part of the rate filing review process. Hearings are common for large LTC rate increases and may significantly extend the approval timeline.',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter US state or territory code identifying the state Department of Insurance (DOI) to which this rate filing is submitted. Each state has independent rate regulation authority; a single product rate change may require separate filings per state.. Valid values are `^[A-Z]{2}$`',
    `line_of_business` STRING COMMENT 'Regulatory line of business classification for the rate filing as defined by NAIC and state DOI reporting standards. Determines the applicable rate regulation statutes and actuarial certification requirements.. Valid values are `life|annuity|health|ltc|disability`',
    `loss_ratio_current` DECIMAL(18,2) COMMENT 'The current (pre-filing) loss ratio for the affected product line and policy forms, expressed as a decimal (e.g., 0.85 = 85%). A key actuarial metric supporting the rate change justification; high loss ratios indicate inadequate current rates.',
    `loss_ratio_projected` DECIMAL(18,2) COMMENT 'The projected loss ratio following implementation of the proposed rate change, expressed as a decimal. Demonstrates to the DOI that the revised rates will achieve actuarial adequacy and rate stability.',
    `ltc_rate_increase_flag` BOOLEAN COMMENT 'Indicates whether this filing is a Long-Term Care (LTC) rate increase filing, which is subject to heightened regulatory scrutiny, consumer notification requirements, and actuarial certification standards under the NAIC LTC Insurance Model Regulation.',
    `policy_form_numbers` STRING COMMENT 'Comma-separated list of policy form numbers (as approved by the DOI) to which the rate filing applies. Policy forms are the standardized contract templates approved by the state DOI; rate filings are tied to specific approved forms.',
    `prior_filing_number` STRING COMMENT 'Filing number of the immediately preceding approved rate filing for the same product line and jurisdiction. Establishes the rate revision history chain and allows comparison of current vs. prior approved rates.',
    `product_line` STRING COMMENT 'Broad insurance product line classification for the rate filing (e.g., Term Life, Whole Life (WL), Universal Life (UL), Long-Term Care (LTC), Annuity). Determines applicable regulatory framework and actuarial standards. [ENUM-REF-CANDIDATE: term_life|whole_life|universal_life|variable_life|ltc|annuity|disability_income|accidental_death — promote to reference product]',
    `proposed_effective_date` DATE COMMENT 'Date on which the company proposes the new or revised rates to become effective for new business or in-force policies. Subject to DOI approval for prior approval states; may differ from the approved effective date.',
    `rate_change_percentage` DECIMAL(18,2) COMMENT 'The percentage change in premium rates proposed in this filing relative to the currently approved rates. Positive values indicate a rate increase; negative values indicate a rate decrease. Critical metric for actuarial justification and DOI review. For LTC rate increase filings, subject to heightened regulatory scrutiny.',
    `rate_change_type` STRING COMMENT 'Directional classification of the rate change proposed in this filing. Distinguishes between rate increases, decreases, no-change filings (e.g., non-forfeiture value updates), and new rate filings for newly introduced products.. Valid values are `increase|decrease|no_change|new_rate`',
    `rate_stability_certification_flag` BOOLEAN COMMENT 'Indicates whether the filing includes an actuarial certification of rate stability as required by the NAIC LTC Insurance Model Regulation. Rate stability certifications attest that the proposed rates are not expected to require future increases.',
    `serff_tracking_number` STRING COMMENT 'Tracking number assigned by the NAIC System for Electronic Rate and Form Filing (SERFF) upon submission of the rate filing to the state DOI. Serves as the authoritative cross-reference between the companys internal records and the state regulatory portal.',
    `submission_date` DATE COMMENT 'Date on which the rate filing was formally submitted to the state Department of Insurance (DOI). Marks the start of the regulatory review clock for prior approval states and establishes the compliance timeline for file-and-use states.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the rate filing record was most recently updated in the compliance system. Supports audit trail requirements, change tracking, and data lineage for the Silver layer.',
    `withdrawal_date` DATE COMMENT 'Date on which the company voluntarily withdrew the rate filing from DOI review. Null for filings not withdrawn. Withdrawal may occur due to actuarial revisions, regulatory feedback, or business strategy changes.',
    CONSTRAINT pk_rate_filing PRIMARY KEY(`rate_filing_id`)
) COMMENT 'Record of premium rate and non-forfeiture value filings submitted to state DOIs for approval or notification. Captures product line, filing type (new rate, rate revision, LTC rate increase), filing method (prior approval, file-and-use), state, actuarial justification reference, proposed effective date, DOI submission date, approval status, approved effective date, and rate change percentage. Supports compliance with state rate regulation requirements.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`jurisdiction_license` (
    `jurisdiction_license_id` BIGINT COMMENT 'Unique surrogate identifier for each jurisdiction license record in the Silver layer. Primary key for the jurisdiction_license data product.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: License renewal fees, statutory deposit requirements, and state compliance costs are allocated to cost centers by jurisdiction. Insurance companies track licensing costs by state/cost center for expen',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Licenses are issued to legal entities. Fundamental regulatory relationship - each legal entity must be licensed in jurisdictions where it operates. Required for regulatory compliance tracking.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Jurisdiction licenses have associated certificate documents, renewal notices, and DOI correspondence stored in the document system. Compliance teams need to retrieve the actual license certificate doc',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Jurisdiction licenses are maintained to satisfy regulatory obligations for authority to transact insurance business. The license describes the authority granted, while the obligation describes the req',
    `admitted_status` STRING COMMENT 'Indicates whether the company is admitted (licensed and subject to state guaranty fund protection), non-admitted, or writing on a surplus lines basis in the jurisdiction. Affects policyholder protections and regulatory requirements.. Valid values are `admitted|non_admitted|surplus_lines`',
    `annual_statement_filing_due_date` DATE COMMENT 'The date by which the company must file its NAIC Annual Statement (statutory financial statement) with the DOI for this jurisdiction. Typically March 1 for most states but may vary. Drives the regulatory filing calendar.',
    `authorized_lines_of_business` STRING COMMENT 'Comma-separated list or description of the specific lines of business authorized under this license (e.g., Life, Annuity, Variable Life, Variable Annuity, Accident and Health). Governs which product types may be sold in the jurisdiction.',
    `compliance_officer_name` STRING COMMENT 'Name of the companys designated compliance officer or regulatory contact responsible for managing the license and DOI relationship in this jurisdiction. Used for regulatory correspondence and examination coordination.',
    `domicile_state_code` STRING COMMENT 'Two-letter USPS code for the state in which the company is domiciled (chartered). Distinguishes the home state license from foreign state licenses and determines which states insurance laws govern the companys primary regulatory oversight.. Valid values are `^[A-Z]{2}$`',
    `effective_date` DATE COMMENT 'The date on which the Certificate of Authority or license became effective and the company was first authorized to transact the specified line of business in the jurisdiction. Marks the start of the binding authorization period.',
    `expiration_date` DATE COMMENT 'The date on which the current license term expires and renewal is required to maintain authorization. Null for perpetual licenses that do not require periodic renewal. Drives the renewal calendar and compliance alerts.',
    `fein` STRING COMMENT 'The Federal Employer Identification Number (FEIN) of the company as registered with the IRS. Required on certain state DOI filings and tax-related regulatory submissions. Also known as Taxpayer Identification Number (TIN).. Valid values are `^[0-9]{2}-[0-9]{7}$`',
    `guaranty_fund_member_flag` BOOLEAN COMMENT 'Indicates whether the company is a member of the state life and health guaranty association for this jurisdiction. Admitted carriers are typically required to be members. Relevant for policyholder protection disclosures and NAIC reporting.',
    `is_domestic` BOOLEAN COMMENT 'Indicates whether this license is a domestic (home state) license (True) or a foreign state license (False). Domestic licenses are issued by the state of domicile; foreign licenses are issued by other states where the company is admitted to transact business.',
    `issuing_authority` STRING COMMENT 'Name of the regulatory body that issued the license (e.g., California Department of Insurance, New York State Department of Financial Services). Identifies the specific DOI or equivalent authority responsible for the license.',
    `issuing_authority_contact` STRING COMMENT 'Contact information (address, phone, or email) for the issuing DOI or regulatory authority. Used for correspondence, renewal submissions, and regulatory inquiries.',
    `jurisdiction_name` STRING COMMENT 'Full legal name of the state or territory jurisdiction (e.g., California, New York, Puerto Rico, District of Columbia). Complements the state code for display and reporting purposes.',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter USPS state or territory code identifying the jurisdiction in which the license is held (e.g., CA, NY, TX, PR, DC). Used to validate that the company is authorized to write business in the state before policy issuance.. Valid values are `^[A-Z]{2}$`',
    `last_examination_date` DATE COMMENT 'The date of the most recent market conduct or financial examination conducted by the DOI in this jurisdiction. Used to track examination cycles and anticipate upcoming examinations per NAIC examination standards.',
    `license_condition_flag` BOOLEAN COMMENT 'Indicates whether the DOI has imposed any conditions, restrictions, or limitations on this license. When True, the license_conditions field contains the details. Conditions may restrict product types, distribution channels, or require enhanced reporting.',
    `license_conditions` STRING COMMENT 'Free-text description of any conditions, restrictions, or limitations imposed by the DOI on this license. Examples include restrictions on writing new business, requirements for enhanced consumer disclosures, or limitations on specific product features. Populated only when license_condition_flag is True.',
    `license_number` STRING COMMENT 'The official license or Certificate of Authority (COA) number assigned by the state Department of Insurance (DOI) to the company for the given jurisdiction. This is the externally-known business identifier used in regulatory filings and correspondence with the DOI.',
    `license_status` STRING COMMENT 'Current lifecycle status of the jurisdiction license as maintained by the state DOI. Active indicates the company is authorized to transact business. Suspended or revoked statuses trigger immediate cessation of new business writing in the jurisdiction.. Valid values are `active|suspended|revoked|expired|pending|surrendered`',
    `license_type` STRING COMMENT 'Classification of the insurance license by product line authorized. Determines which lines of business the company is permitted to transact in the jurisdiction. Variable product types are subject to additional SEC/FINRA oversight. [ENUM-REF-CANDIDATE: life|annuity|variable_life|variable_annuity|accident_health|disability_income — promote to reference product if additional lines are added]. Valid values are `life|annuity|variable_life|variable_annuity|accident_health`',
    `minimum_capital_requirement` DECIMAL(18,2) COMMENT 'The minimum capital and surplus amount required by the jurisdictions DOI for the company to maintain its license, denominated in USD. Linked to Risk-Based Capital (RBC) requirements and solvency monitoring.',
    `naic_company_code` STRING COMMENT 'The five-digit NAIC company code assigned to the insurer. Used in all NAIC regulatory filings, state financial examinations, and market conduct reporting to uniquely identify the company across all jurisdictions.. Valid values are `^[0-9]{5}$`',
    `next_examination_due_date` DATE COMMENT 'The anticipated or scheduled date for the next DOI examination in this jurisdiction. Typically every 3-5 years per NAIC standards. Used for compliance planning and resource allocation.',
    `notes` STRING COMMENT 'Free-text field for additional compliance notes, DOI correspondence summaries, or internal observations related to the license. Used by the compliance team to document material events not captured in structured fields.',
    `original_issue_date` DATE COMMENT 'The date on which the company was first granted a license in this jurisdiction for this license type, regardless of subsequent renewals. Establishes the historical tenure of authorization in the jurisdiction.',
    `record_created_timestamp` TIMESTAMP COMMENT 'The timestamp when this jurisdiction license record was first created in the compliance data product. Provides audit trail for record provenance in the Silver layer.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this jurisdiction license record was most recently updated in the compliance data product. Supports change tracking, audit trails, and incremental data pipeline processing.',
    `registered_agent_address` STRING COMMENT 'Physical address of the registered agent for service of process in the jurisdiction. Required for legal and regulatory correspondence. Maintained as confidential business contact information.',
    `registered_agent_name` STRING COMMENT 'Name of the companys registered agent for service of process in the jurisdiction. Required by most states as a condition of licensure. The registered agent receives legal notices and regulatory correspondence on behalf of the company.',
    `reinstatement_date` DATE COMMENT 'The date on which a previously suspended or lapsed license was reinstated by the DOI. Null if the license has never been reinstated. Marks the resumption of authorization to transact business.',
    `renewal_application_date` DATE COMMENT 'The date on which the company submitted the renewal application to the state DOI. Used to confirm timely filing and to calculate days-before-expiration for compliance reporting.',
    `renewal_date` DATE COMMENT 'The date by which the renewal application and associated fees must be submitted to the DOI to avoid lapse of authorization. May differ from expiration_date where the DOI requires advance filing.',
    `renewal_fee_amount` DECIMAL(18,2) COMMENT 'The monetary amount paid or payable to the state DOI for license renewal, denominated in USD. Tracked for budgeting, accounts payable, and regulatory expense reporting.',
    `renewal_status` STRING COMMENT 'Current status of the renewal process for the license. Tracks whether the renewal application has been submitted, is under DOI review, approved, or has lapsed. Critical for compliance monitoring to ensure continuous authorization.. Valid values are `not_due|submitted|approved|pending_review|rejected|lapsed`',
    `restriction_type` STRING COMMENT 'Categorical classification of the type of restriction or condition imposed on the license by the DOI. Enables structured reporting and monitoring of restricted licenses across jurisdictions.. Valid values are `none|product_restriction|distribution_restriction|geographic_restriction|reporting_requirement|consent_order`',
    `revocation_date` DATE COMMENT 'The date on which the DOI permanently revoked the license, if applicable. Null for active or suspended licenses. A revoked license requires a new application process to re-enter the jurisdiction.',
    `statutory_deposit_amount` DECIMAL(18,2) COMMENT 'The amount of securities or cash deposited with the state treasury or DOI as a condition of licensure in the jurisdiction, denominated in USD. Required by certain states as a financial security requirement for admitted carriers.',
    `statutory_deposit_type` STRING COMMENT 'Type of asset held on deposit with the state as a condition of licensure. Determines the nature of the financial security arrangement and applicable valuation methods under SAP.. Valid values are `cash|securities|letter_of_credit|none`',
    `suspension_date` DATE COMMENT 'The date on which the DOI suspended the license, if applicable. Null for licenses that have never been suspended. Triggers immediate cessation of new business writing and notification to the Policy Administration System.',
    `suspension_reason` STRING COMMENT 'Description of the reason provided by the DOI for suspending the license. Populated only when suspension_date is not null. Used for regulatory response planning and remediation tracking.',
    `variable_product_flag` BOOLEAN COMMENT 'Indicates whether this license authorizes the sale of variable insurance products (variable life or variable annuity) that are subject to SEC and FINRA oversight in addition to state DOI regulation. True triggers additional compliance checks.',
    CONSTRAINT pk_jurisdiction_license PRIMARY KEY(`jurisdiction_license_id`)
) COMMENT 'Master record of the companys Certificate of Authority (COA) and licenses to transact insurance business in each state and territory. Captures jurisdiction, license type (life, annuity, variable life, variable annuity), license number, effective date, renewal date, renewal status, authorized lines of business, and any license conditions or restrictions imposed by the DOI. Ensures the company only writes business in jurisdictions where it is properly licensed.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`state_regulation` (
    `state_regulation_id` BIGINT COMMENT 'Unique identifier for the state-specific insurance regulation record. Primary key.',
    `primary_superseded_by_regulation_state_regulation_id` BIGINT COMMENT 'Reference to the newer state regulation that replaces this regulation, if applicable. Null if not superseded.',
    `accelerated_death_benefit_regulation_flag` BOOLEAN COMMENT 'Indicates whether the state has specific regulations governing accelerated death benefit riders. True if ADB regulations apply, False if not.',
    `best_interest_standard_flag` BOOLEAN COMMENT 'Indicates whether the state has adopted a best interest standard for annuity sales (similar to Regulation Best Interest). True if best interest standard applies, False if not.',
    `compliance_notes` STRING COMMENT 'Internal notes documenting compliance considerations, implementation guidance, or special handling requirements for this state regulation.',
    `contestability_period_months` STRING COMMENT 'Number of months during which the insurer may contest a life insurance policy for material misrepresentation, as mandated by state law. Typically 24 months but may vary by state.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this state regulation record was first created in the system.',
    `effective_date` DATE COMMENT 'Date when the state-specific regulation becomes enforceable and applicable to insurance operations.',
    `expiration_date` DATE COMMENT 'Date when the state regulation ceases to be in effect, if applicable. Null for regulations with no defined end date.',
    `form_filing_method` STRING COMMENT 'State-mandated method for submitting and approving policy forms (prior approval required before use, file and use after DOI review, use and file with post-use notification, no filing required).. Valid values are `prior_approval|file_and_use|use_and_file|no_filing`',
    `free_look_period_days` STRING COMMENT 'Number of days the policyholder has to review and cancel a newly issued policy without penalty, as mandated by state regulation. Varies by state and product type.',
    `grace_period_days` STRING COMMENT 'Number of days after premium due date during which coverage remains in force without lapse, as required by state regulation. Typically 30-31 days but varies by state.',
    `illustration_regulation_flag` BOOLEAN COMMENT 'Indicates whether the state has specific regulations governing life insurance policy illustrations. True if illustration rules apply, False if not.',
    `insurable_interest_requirement` STRING COMMENT 'State-specific definition and requirements for establishing insurable interest in life insurance transactions. Describes when insurable interest must exist (at inception, at death, etc.).',
    `interest_rate_guarantee_minimum` DECIMAL(18,2) COMMENT 'State-mandated minimum guaranteed interest rate for cash value accumulation in life insurance and annuity products. Expressed as a decimal (e.g., 0.0200 for 2%).',
    `issuing_authority` STRING COMMENT 'Name of the state regulatory body that issued or enforces this regulation (e.g., California Department of Insurance, New York Department of Financial Services).',
    `jurisdiction_name` STRING COMMENT 'Full name of the state or territory regulatory jurisdiction (e.g., California, New York, Texas).',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter state code identifying the regulatory jurisdiction (e.g., CA, NY, TX). Aligns with NAIC state codes.. Valid values are `^[A-Z]{2}$`',
    `last_amended_date` DATE COMMENT 'Date when the state regulation was last amended or revised. Null if no amendments have been made since original enactment.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this state regulation record was last modified in the system.',
    `long_term_care_partnership_flag` BOOLEAN COMMENT 'Indicates whether the state participates in the Long-Term Care Partnership Program, allowing policyholders to protect assets while qualifying for Medicaid. True if partnership state, False if not.',
    `minimum_cash_surrender_value_percentage` DECIMAL(18,2) COMMENT 'State-mandated minimum cash surrender value as a percentage of premiums paid or reserves, as required by nonforfeiture laws. Null if no state-specific requirement.',
    `minimum_death_benefit_amount` DECIMAL(18,2) COMMENT 'State-mandated minimum death benefit amount for life insurance policies issued in the jurisdiction. Null if no state-specific minimum applies.',
    `nonforfeiture_method` STRING COMMENT 'State-mandated method for calculating nonforfeiture values (Commissioners Reserve Valuation Method, Commissioners Extended Term Method, Cash Surrender Value Method).. Valid values are `commissioners_reserve|commissioners_extended|cash_surrender`',
    `nonforfeiture_requirement_flag` BOOLEAN COMMENT 'Indicates whether the state mandates nonforfeiture benefits (cash surrender value, reduced paid-up insurance, extended term insurance) for this product type. True if required, False if not.',
    `product_line` STRING COMMENT 'Insurance product line(s) to which this state regulation applies (e.g., Life, Annuity, Variable Life, Variable Annuity, Long-Term Care). May contain multiple values separated by semicolons.',
    `rate_filing_method` STRING COMMENT 'State-mandated method for submitting and approving insurance rates (prior approval required before use, file and use after DOI review, use and file with post-use notification, no filing required).. Valid values are `prior_approval|file_and_use|use_and_file|no_filing`',
    `regulation_citation` STRING COMMENT 'Official citation reference to the state statute, regulation, or administrative code section that establishes this requirement (e.g., California Insurance Code Section 10113.71).',
    `regulation_description` STRING COMMENT 'Detailed description of the state-specific regulatory requirement, including key provisions, applicability conditions, and compliance obligations.',
    `regulation_status` STRING COMMENT 'Current lifecycle status of the state regulation (active, superseded by newer regulation, pending approval, withdrawn).. Valid values are `active|superseded|pending|withdrawn`',
    `regulation_type` STRING COMMENT 'Category of state-specific insurance regulation (policy form approval, rate filing requirements, nonforfeiture standards, free look period, grace period, replacement regulations).. Valid values are `policy_form|rate_filing|nonforfeiture|free_look|grace_period|replacement`',
    `replacement_notice_required_flag` BOOLEAN COMMENT 'Indicates whether the state requires written notice to the existing insurer when a policy replacement is proposed. True if notice required, False if not.',
    `replacement_regulation_flag` BOOLEAN COMMENT 'Indicates whether the state has specific regulations governing policy replacement transactions (1035 exchanges, internal replacements). True if state has replacement rules, False if not.',
    `serff_filing_required_flag` BOOLEAN COMMENT 'Indicates whether the state requires rate and form filings to be submitted through the NAIC SERFF system. True if SERFF required, False if alternative methods allowed.',
    `stoli_prohibition_flag` BOOLEAN COMMENT 'Indicates whether the state has enacted specific prohibitions against stranger-originated life insurance transactions. True if STOLI prohibited, False if not.',
    `suicide_exclusion_period_months` STRING COMMENT 'Number of months during which death by suicide is excluded from life insurance coverage, as mandated by state law. Typically 24 months but may vary by state.',
    `suitability_review_required_flag` BOOLEAN COMMENT 'Indicates whether the state mandates suitability reviews and documentation for annuity sales. True if suitability review required, False if not.',
    `variable_product_registration_required_flag` BOOLEAN COMMENT 'Indicates whether the state requires separate registration or approval for variable life and variable annuity products beyond standard form filing. True if additional registration required, False if not.',
    CONSTRAINT pk_state_regulation PRIMARY KEY(`state_regulation_id`)
) COMMENT 'Reference table of state-specific insurance regulatory requirements, variations, and effective dates by jurisdiction. Captures state DOI-specific rules for policy forms, rate filings, nonforfeiture requirements, free look periods, grace periods, and replacement regulations that vary by state.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`sar_filing` (
    `sar_filing_id` BIGINT COMMENT 'Unique identifier for the SAR filing record. Primary key.',
    `aml_case_id` BIGINT COMMENT 'Reference to the AML case investigation that resulted in this SAR filing.',
    `in_force_policy_id` BIGINT COMMENT 'Reference to the life insurance or annuity policy involved in the suspicious activity, if applicable.',
    `party_id` BIGINT COMMENT 'Reference to the policyholder who is the subject of the suspicious activity report.',
    `plan_id` BIGINT COMMENT 'Foreign key linking to product.plan. Business justification: SAR filings reference the specific insurance plan involved in suspicious activity. FinCEN BSA reporting for insurance requires product-level identification. product_type on sar_filing is a denormalize',
    `prior_sar_filing_id` BIGINT COMMENT 'Self-referencing FK on sar_filing (prior_sar_filing_id)',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: SAR filings fulfill FinCEN AML/BSA regulatory obligations. The obligation defines the filing deadline and requirements.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: SAR filings are formal FinCEN documents with narrative descriptions and supporting evidence required by BSA/AML regulations. Critical for AML regulatory reporting and FinCEN submission tracking in Lif',
    `trade_id` BIGINT COMMENT 'Foreign key linking to investment.trade. Business justification: SAR filings report suspicious trading activity (structuring, unusual patterns, STOLI indicators). Real business process: suspicious transaction reporting, FinCEN filing, AML compliance. Required for i',
    `acknowledgment_date` DATE COMMENT 'Date when FinCEN acknowledged receipt of the SAR filing. Format: yyyy-MM-dd.',
    `activity_end_date` DATE COMMENT 'Date when the suspicious activity ended or was last observed. May be null for ongoing activity. Format: yyyy-MM-dd.',
    `activity_start_date` DATE COMMENT 'Date when the suspicious activity began or was first observed. Format: yyyy-MM-dd.',
    `approval_date` DATE COMMENT 'Date when the SAR filing was approved for submission to FinCEN. Format: yyyy-MM-dd.',
    `approver_name` STRING COMMENT 'Full name of the senior compliance officer or manager who approved the SAR filing for submission.',
    `confidentiality_flag` BOOLEAN COMMENT 'Indicates that this SAR filing is subject to strict confidentiality requirements under the Bank Secrecy Act. Always True for SAR filings.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this SAR filing record was first created in the system. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the transaction amount (e.g., USD, EUR, GBP).. Valid values are `^[A-Z]{3}$`',
    `detection_method` STRING COMMENT 'Method by which the suspicious activity was detected: automated monitoring system, manual review, customer complaint, law enforcement inquiry, regulatory examination, or other.. Valid values are `automated_monitoring|manual_review|customer_complaint|law_enforcement_inquiry|regulatory_exam|other`',
    `filing_date` DATE COMMENT 'Date when the SAR was filed with FinCEN. Format: yyyy-MM-dd.',
    `filing_reference_number` STRING COMMENT 'Internal reference number assigned to this SAR filing for tracking and audit purposes.',
    `filing_status` STRING COMMENT 'Current status of the SAR filing in the internal workflow: draft (being prepared), pending_review (awaiting compliance review), approved (ready for submission), submitted (sent to FinCEN), acknowledged (FinCEN confirmation received), rejected (FinCEN rejected submission).. Valid values are `draft|pending_review|approved|submitted|acknowledged|rejected`',
    `filing_type` STRING COMMENT 'Type of SAR filing: initial (first report of suspicious activity), continuing (follow-up to prior SAR), corrected (correction to previously filed SAR), or amended (substantive change to prior SAR).. Valid values are `initial|continuing|corrected|amended`',
    `fincen_bsa_number` STRING COMMENT 'Unique identifier assigned by FinCEN upon successful submission of the SAR. Also known as the BSA Identifier or acknowledgment number.',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter state code where the suspicious activity occurred or where the policy was issued.. Valid values are `^[A-Z]{2}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when this SAR filing record was last modified. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `law_enforcement_agency` STRING COMMENT 'Name of the law enforcement agency contacted regarding this suspicious activity, if applicable.',
    `law_enforcement_contact_flag` BOOLEAN COMMENT 'Indicates whether law enforcement has been contacted regarding this suspicious activity. True if contacted, False otherwise.',
    `narrative_description` STRING COMMENT 'Detailed narrative description of the suspicious activity, including facts, circumstances, and reasons for suspicion. This is the core content of the SAR filing.',
    `preparer_name` STRING COMMENT 'Full name of the compliance officer or employee who prepared the SAR filing.',
    `prior_sar_reference` STRING COMMENT 'Reference to a prior SAR filing if this is a continuing, corrected, or amended SAR. Contains the FinCEN BSA ID of the prior SAR.',
    `rejection_date` DATE COMMENT 'Date when FinCEN rejected the SAR filing due to errors or incomplete information. Format: yyyy-MM-dd.',
    `rejection_reason` STRING COMMENT 'Reason provided by FinCEN for rejecting the SAR filing, if applicable.',
    `subject_address` STRING COMMENT 'Full address of the subject involved in the suspicious activity.',
    `subject_date_of_birth` DATE COMMENT 'Date of birth of the individual subject, if applicable. Format: yyyy-MM-dd.',
    `subject_name` STRING COMMENT 'Full legal name of the individual or entity that is the subject of the suspicious activity report.',
    `subject_tax_number` STRING COMMENT 'Tax identification number of the subject: Social Security Number (SSN) for individuals or Employer Identification Number (EIN) for entities.',
    `subject_type` STRING COMMENT 'Type of subject involved in the suspicious activity: individual (natural person), entity (organization/business), or unknown.. Valid values are `individual|entity|unknown`',
    `submission_timestamp` TIMESTAMP COMMENT 'Precise date and time when the SAR was electronically submitted to FinCEN. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `suspicious_activity_type` STRING COMMENT 'Category or type of suspicious activity being reported (e.g., structuring, money laundering, terrorist financing, fraud, identity theft). May contain multiple types separated by semicolons. [ENUM-REF-CANDIDATE: structuring|money_laundering|terrorist_financing|fraud|identity_theft|elder_financial_exploitation|insurance_fraud|premium_financing_abuse|stoli|tax_evasion|bribery|embezzlement — promote to reference product]',
    `transaction_amount` DECIMAL(18,2) COMMENT 'Total dollar amount of the transaction(s) involved in the suspicious activity. Aggregate amount if multiple transactions.',
    CONSTRAINT pk_sar_filing PRIMARY KEY(`sar_filing_id`)
) COMMENT 'Transactional record of Suspicious Activity Reports (SARs) filed with FinCEN under the Bank Secrecy Act (BSA) for life insurance and annuity transactions. Captures SAR type (initial/continuing), filing date, FinCEN BSA ID, suspicious activity date range, transaction amounts, subject information, narrative description, filing status, and acknowledgment receipt. Required for AML/BSA compliance.';

